"""
Core Algorithms Package - Root convenience wrapper

Delegates all imports to server/quantum_ai/core_algorithms/ which contains
the actual algorithm implementations. This file exists for standalone usage
outside of the quantum_bridge server context.
"""

import sys
import os
import importlib

_server_ca = os.path.normpath(os.path.join(os.path.dirname(__file__), '..', 'server', 'quantum_ai', 'core_algorithms'))

if os.path.isdir(_server_ca):
    for _f in os.listdir(_server_ca):
        if _f.endswith('.py') and _f != '__init__.py':
            _mod_name = _f[:-3]
            _mod_path = os.path.join(_server_ca, _f)
            _spec = importlib.util.spec_from_file_location(
                f"core_algorithms.{_mod_name}", _mod_path
            )
            if _spec and _spec.loader:
                _mod = importlib.util.module_from_spec(_spec)
                sys.modules[f"core_algorithms.{_mod_name}"] = _mod
                try:
                    _spec.loader.exec_module(_mod)
                except Exception:
                    pass

    _init_path = os.path.join(_server_ca, '__init__.py')
    if os.path.exists(_init_path):
        _spec = importlib.util.spec_from_file_location(
            "_core_algorithms_server", _init_path
        )
        if _spec and _spec.loader:
            _mod = importlib.util.module_from_spec(_spec)
            try:
                _spec.loader.exec_module(_mod)
                for _name in dir(_mod):
                    if not _name.startswith('_'):
                        globals()[_name] = getattr(_mod, _name)
            except Exception:
                pass

server/comms/signaling.ts.content:
import WebSocket, { WebSocketServer } from "ws";
import { v4 as uuid } from "uuid";
import { Server } from "http";

interface SignalMessage {
  type: string;
  roomId?: string;
  payload?: any;
  sender?: string;
  target?: string;
  targetUserId?: string;
}

interface ConnectedUser {
  id: string;
  displayName: string;
  ws: WebSocket;
  deviceId: string;
  lastActivity: Date;
  inCall: boolean;
  currentRoomId?: string;
}

const connectedUsers = new Map<string, ConnectedUser>();
const roomMap = new Map<string, Set<WebSocket>>();
const pendingCalls = new Map<string, {
  callerId: string;
  callerName: string;
  roomId: string;
  callType: string;
  timestamp: Date;
}>();

export function getConnectedUsers(): ConnectedUser[] {
  return Array.from(connectedUsers.values()).map(user => ({
    ...user,
    ws: undefined as any,
  }));
}

export function getUserSocket(userId: string): WebSocket | undefined {
  return connectedUsers.get(userId)?.ws;
}

export function broadcastToAll(message: any, excludeUserId?: string): void {
  const msgStr = JSON.stringify(message);
  connectedUsers.forEach((user, id) => {
    if (id !== excludeUserId && user.ws.readyState === WebSocket.OPEN) {
      user.ws.send(msgStr);
    }
  });
}

export function initSignalingServer(httpServer: Server) {
  const wss = new WebSocketServer({ server: httpServer, path: "/ws" });

  function joinRoom(roomId: string, ws: WebSocket) {
    if (!roomMap.has(roomId)) roomMap.set(roomId, new Set());
    roomMap.get(roomId)!.add(ws);
  }

  function leaveRoom(roomId: string, ws: WebSocket) {
    const room = roomMap.get(roomId);
    if (room) {
      room.delete(ws);
      if (room.size === 0) {
        roomMap.delete(roomId);
      }
    }
  }

  function broadcastPresence() {
    const onlineUsers = Array.from(connectedUsers.values()).map(user => ({
      id: user.id,
      displayName: user.displayName,
      deviceId: user.deviceId,
      inCall: user.inCall,
      lastActivity: user.lastActivity,
    }));

    const message = JSON.stringify({
      type: "presence-update",
      users: onlineUsers,
    });

    connectedUsers.forEach((user) => {
      if (user.ws.readyState === WebSocket.OPEN) {
        user.ws.send(message);
      }
    });
  }

  wss.on("connection", (ws, req) => {
    const url = new URL(req.url || "", `http://${req.headers.host}`);
    const roomId = url.searchParams.get("room");
    const userId = url.searchParams.get("userId") || `user_${uuid().substring(0, 8)}`;
    const displayName = url.searchParams.get("name") || `User-${userId.substring(0, 6)}`;
    const deviceId = url.searchParams.get("deviceId") || uuid();

    const clientId = uuid();
    (ws as any).clientId = clientId;
    (ws as any).userId = userId;

    connectedUsers.set(userId, {
      id: userId,
      displayName: decodeURIComponent(displayName),
      ws,
      deviceId,
      lastActivity: new Date(),
      inCall: false,
    });

    console.log(`[Presence] User connected: ${decodeURIComponent(displayName)} (${userId}) - Total users: ${connectedUsers.size}`);
    console.log(`[Presence] All connected users: ${Array.from(connectedUsers.values()).map(u => u.displayName).join(", ")}`);

    if (roomId) {
      joinRoom(roomId, ws);
    }

    ws.send(JSON.stringify({
      type: "connected",
      userId,
      clientId,
      totalOnline: connectedUsers.size,
    }));

    broadcastPresence();

    ws.on("message", (data) => {
      try {
        const msg: SignalMessage = JSON.parse(data.toString());

        const user = connectedUsers.get(userId);
        if (user) {
          user.lastActivity = new Date();
        }

        switch (msg.type) {
          case "register":
            if (user && msg.payload?.displayName) {
              user.displayName = msg.payload.displayName;
              broadcastPresence();
            }
            break;

          case "call-user":
            console.log(`[Signaling] Call request from ${user?.displayName} to ${msg.targetUserId}`);
            console.log(`[Signaling] Connected users: ${Array.from(connectedUsers.keys()).join(", ")}`);
            const targetUser = connectedUsers.get(msg.targetUserId!);
            if (targetUser && targetUser.ws.readyState === WebSocket.OPEN) {
              console.log(`[Signaling] Target user found: ${targetUser.displayName}`);
              const callRoomId = msg.roomId || `call_${uuid()}`;

              pendingCalls.set(callRoomId, {
                callerId: userId,
                callerName: user?.displayName || userId,
                roomId: callRoomId,
                callType: msg.payload?.callType || "video",
                timestamp: new Date(),
              });

              targetUser.ws.send(JSON.stringify({
                type: "incoming-call",
                callerId: userId,
                callerName: user?.displayName || userId,
                roomId: callRoomId,
                callType: msg.payload?.callType || "video",
              }));

              ws.send(JSON.stringify({
                type: "call-initiated",
                roomId: callRoomId,
                targetUserId: msg.targetUserId,
                status: "ringing",
              }));

              if (user) {
                user.inCall = true;
                user.currentRoomId = callRoomId;
              }
              broadcastPresence();
            } else {
              console.log(`[Signaling] Target user ${msg.targetUserId} NOT found or offline`);
              ws.send(JSON.stringify({
                type: "call-failed",
                reason: "user-offline",
                targetUserId: msg.targetUserId,
              }));
            }
            break;

          case "accept-call":
            const pendingCall = pendingCalls.get(msg.roomId!);
            if (pendingCall) {
              const caller = connectedUsers.get(pendingCall.callerId);
              if (caller && caller.ws.readyState === WebSocket.OPEN) {
                caller.ws.send(JSON.stringify({
                  type: "call-accepted",
                  roomId: msg.roomId,
                  acceptedBy: userId,
                  acceptedByName: user?.displayName,
                }));
              }

              joinRoom(msg.roomId!, ws);
              if (caller) {
                joinRoom(msg.roomId!, caller.ws);
              }

              if (user) {
                user.inCall = true;
                user.currentRoomId = msg.roomId;
              }
              broadcastPresence();
            }
            break;

          case "decline-call":
            const declinedCall = pendingCalls.get(msg.roomId!);
            if (declinedCall) {
              const caller = connectedUsers.get(declinedCall.callerId);
              if (caller && caller.ws.readyState === WebSocket.OPEN) {
                caller.ws.send(JSON.stringify({
                  type: "call-declined",
                  roomId: msg.roomId,
                  declinedBy: userId,
                  reason: msg.payload?.reason || "declined",
                }));
                caller.inCall = false;
                caller.currentRoomId = undefined;
              }
              pendingCalls.delete(msg.roomId!);
              broadcastPresence();
            }
            break;

          case "end-call":
            if (msg.roomId) {
              const room = roomMap.get(msg.roomId);
              if (room) {
                room.forEach((peer) => {
                  if (peer !== ws && peer.readyState === WebSocket.OPEN) {
                    peer.send(JSON.stringify({
                      type: "call-ended",
                      roomId: msg.roomId,
                      endedBy: userId,
                    }));
                  }
                  const peerUserId = (peer as any).userId;
                  const peerUser = connectedUsers.get(peerUserId);
                  if (peerUser) {
                    peerUser.inCall = false;
                    peerUser.currentRoomId = undefined;
                  }
                });
                leaveRoom(msg.roomId, ws);
              }
              if (user) {
                user.inCall = false;
                user.currentRoomId = undefined;
              }
              pendingCalls.delete(msg.roomId);
              broadcastPresence();
            }
            break;

          case "join":
            if (msg.roomId) {
              joinRoom(msg.roomId, ws);
              const room = roomMap.get(msg.roomId);
              if (room) {
                room.forEach((peer) => {
                  if (peer !== ws && peer.readyState === WebSocket.OPEN) {
                    peer.send(JSON.stringify({
                      type: "peer-joined",
                      peerId: clientId,
                      userId,
                      displayName: user?.displayName,
                    }));
                  }
                });
              }
            }
            break;

          case "offer":
          case "answer":
          case "ice-candidate":
            if (msg.roomId) {
              const peers = roomMap.get(msg.roomId) || new Set();
              peers.forEach((peer) => {
                if (peer !== ws && peer.readyState === WebSocket.OPEN) {
                  peer.send(JSON.stringify({
                    ...msg,
                    sender: clientId,
                    senderUserId: userId,
                  }));
                }
              });
            }
            break;

          case "heartbeat":
            if (user) {
              user.lastActivity = new Date();
            }
            ws.send(JSON.stringify({ type: "heartbeat-ack" }));
            break;

          default:
            if (msg.roomId) {
              const peers = roomMap.get(msg.roomId) || new Set();
              peers.forEach((peer) => {
                if (peer !== ws && peer.readyState === WebSocket.OPEN) {
                  peer.send(JSON.stringify({ ...msg, sender: clientId }));
                }
              });
            }
        }
      } catch (err) {
        console.error("[signaling] Invalid message", err);
      }
    });

    ws.on("close", () => {
      const user = connectedUsers.get(userId);
      if (user?.currentRoomId) {
        const room = roomMap.get(user.currentRoomId);
        if (room) {
          room.forEach((peer) => {
            if (peer.readyState === WebSocket.OPEN) {
              peer.send(JSON.stringify({
                type: "peer-disconnected",
                userId,
                displayName: user.displayName,
              }));
            }
          });
        }
      }

      console.log(`[Presence] User disconnected: ${user?.displayName || userId} - Remaining users: ${connectedUsers.size - 1}`);
      connectedUsers.delete(userId);

      for (const [roomId, set] of roomMap.entries()) {
        set.delete(ws);
        if (set.size === 0) {
          roomMap.delete(roomId);
        }
      }

      broadcastPresence();
    });

    ws.on("error", (error) => {
      console.error("[signaling] WebSocket error:", error);
    });
  });

  setInterval(() => {
    const now = Date.now();
    connectedUsers.forEach((user, id) => {
      if (now - user.lastActivity.getTime() > 60000) {
        if (user.ws.readyState === WebSocket.OPEN) {
          user.ws.ping();
        }
      }
    });
  }, 30000);

  console.log("[signaling] WebSocket signaling active at /ws");
  return { getConnectedUsers, getUserSocket, broadcastToAll };
}

client/src/hooks/useAudioProcessing.ts.content:
import { useRef, useCallback } from "react";

export interface AudioEnhancementOptions {
  normalize: boolean;
  removeNoise: boolean;
  smoothTransitions: boolean;
  addWarmth: boolean;
  compressionRatio: number;
}

const defaultOptions: AudioEnhancementOptions = {
  normalize: true,
  removeNoise: true,
  smoothTransitions: true,
  addWarmth: true,
  compressionRatio: 3,
};

export function useAudioProcessing() {
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const compressorRef = useRef<DynamicsCompressorNode | null>(null);
  const lowpassRef = useRef<BiquadFilterNode | null>(null);
  const highpassRef = useRef<BiquadFilterNode | null>(null);
  const warmthFilterRef = useRef<BiquadFilterNode | null>(null);

  const initializeAudioContext = useCallback(() => {
    if (!audioContextRef.current) {
      audioContextRef.current = new AudioContext();
    }
    return audioContextRef.current;
  }, []);

  const createProcessingChain = useCallback((ctx: AudioContext, options: AudioEnhancementOptions) => {
    const compressor = ctx.createDynamicsCompressor();
    compressor.threshold.setValueAtTime(-24, ctx.currentTime);
    compressor.knee.setValueAtTime(30, ctx.currentTime);
    compressor.ratio.setValueAtTime(options.compressionRatio, ctx.currentTime);
    compressor.attack.setValueAtTime(0.003, ctx.currentTime);
    compressor.release.setValueAtTime(0.25, ctx.currentTime);
    compressorRef.current = compressor;

    const gainNode = ctx.createGain();
    gainNode.gain.setValueAtTime(1.0, ctx.currentTime);
    gainNodeRef.current = gainNode;

    const lowpass = ctx.createBiquadFilter();
    lowpass.type = "lowpass";
    lowpass.frequency.setValueAtTime(8000, ctx.currentTime);
    lowpass.Q.setValueAtTime(0.5, ctx.currentTime);
    lowpassRef.current = lowpass;

    const highpass = ctx.createBiquadFilter();
    highpass.type = "highpass";
    highpass.frequency.setValueAtTime(80, ctx.currentTime);
    highpass.Q.setValueAtTime(0.5, ctx.currentTime);
    highpassRef.current = highpass;

    const warmthFilter = ctx.createBiquadFilter();
    warmthFilter.type = "peaking";
    warmthFilter.frequency.setValueAtTime(200, ctx.currentTime);
    warmthFilter.Q.setValueAtTime(1.0, ctx.currentTime);
    warmthFilter.gain.setValueAtTime(options.addWarmth ? 3 : 0, ctx.currentTime);
    warmthFilterRef.current = warmthFilter;

    const presenceFilter = ctx.createBiquadFilter();
    presenceFilter.type = "peaking";
    presenceFilter.frequency.setValueAtTime(3000, ctx.currentTime);
    presenceFilter.Q.setValueAtTime(1.0, ctx.currentTime);
    presenceFilter.gain.setValueAtTime(2, ctx.currentTime);

    const analyser = ctx.createAnalyser();
    analyser.fftSize = 2048;
    analyser.smoothingTimeConstant = 0.8;
    analyserRef.current = analyser;

    return { compressor, gainNode, lowpass, highpass, warmthFilter, presenceFilter, analyser };
  }, []);

  const processAudioBlob = useCallback(async (
    audioBlob: Blob,
    options: Partial<AudioEnhancementOptions> = {}
  ): Promise<Blob> => {
    const mergedOptions = { ...defaultOptions, ...options };
    const ctx = initializeAudioContext();

    const arrayBuffer = await audioBlob.arrayBuffer();
    const audioBuffer = await ctx.decodeAudioData(arrayBuffer);

    const offlineCtx = new OfflineAudioContext(
      audioBuffer.numberOfChannels,
      audioBuffer.length,
      audioBuffer.sampleRate
    );

    const source = offlineCtx.createBufferSource();
    source.buffer = audioBuffer;

    const { compressor, gainNode, lowpass, highpass, warmthFilter, presenceFilter } = 
      createProcessingChain(offlineCtx as unknown as AudioContext, mergedOptions);

    source.connect(highpass);
    highpass.connect(lowpass);
    lowpass.connect(warmthFilter);
    warmthFilter.connect(presenceFilter);
    presenceFilter.connect(compressor);
    compressor.connect(gainNode);
    gainNode.connect(offlineCtx.destination);

    source.start();
    const renderedBuffer = await offlineCtx.startRendering();

    const wavBlob = audioBufferToWav(renderedBuffer);
    return wavBlob;
  }, [initializeAudioContext, createProcessingChain]);

  const playEnhancedAudio = useCallback(async (
    audioBlob: Blob,
    options: Partial<AudioEnhancementOptions> = {},
    onEnd?: () => void
  ): Promise<HTMLAudioElement> => {
    const mergedOptions = { ...defaultOptions, ...options };
    const ctx = initializeAudioContext();

    if (ctx.state === "suspended") {
      await ctx.resume();
    }

    const arrayBuffer = await audioBlob.arrayBuffer();
    const audioBuffer = await ctx.decodeAudioData(arrayBuffer);

    const { compressor, gainNode, lowpass, highpass, warmthFilter, presenceFilter, analyser } = 
      createProcessingChain(ctx, mergedOptions);

    const source = ctx.createBufferSource();
    source.buffer = audioBuffer;

    source.connect(highpass);
    highpass.connect(lowpass);
    lowpass.connect(warmthFilter);
    warmthFilter.connect(presenceFilter);
    presenceFilter.connect(compressor);
    compressor.connect(gainNode);
    gainNode.connect(analyser);
    analyser.connect(ctx.destination);

    if (mergedOptions.smoothTransitions && audioBuffer.duration > 0.2) {
      const fadeTime = Math.min(0.05, audioBuffer.duration * 0.1);
      gainNode.gain.setValueAtTime(0, ctx.currentTime);
      gainNode.gain.linearRampToValueAtTime(1.0, ctx.currentTime + fadeTime);

      const duration = audioBuffer.duration;
      if (duration > fadeTime * 2) {
        gainNode.gain.setValueAtTime(1.0, ctx.currentTime + duration - fadeTime);
        gainNode.gain.linearRampToValueAtTime(0, ctx.currentTime + duration);
      }
    }

    source.onended = () => {
      onEnd?.();
    };

    source.start();

    const dummyAudio = new Audio();
    return dummyAudio;
  }, [initializeAudioContext, createProcessingChain]);

  const playAudioFromUrl = useCallback(async (
    url: string,
    options: Partial<AudioEnhancementOptions> = {},
    onEnd?: () => void
  ): Promise<void> => {
    try {
      const response = await fetch(url);
      const blob = await response.blob();
      await playEnhancedAudio(blob, options, onEnd);
    } catch (error) {
      console.error("Failed to play enhanced audio:", error);
      const audio = new Audio(url);
      audio.onended = () => onEnd?.();
      audio.play();
    }
  }, [playEnhancedAudio]);

  const setVolume = useCallback((volume: number) => {
    if (gainNodeRef.current && audioContextRef.current) {
      gainNodeRef.current.gain.setValueAtTime(
        Math.max(0, Math.min(1, volume)),
        audioContextRef.current.currentTime
      );
    }
  }, []);

