import { useState, useRef, useEffect } from "react";
import { useMutation } from "@tanstack/react-query";
import { Cpu, Send, Mic, MicOff, Volume2, X, Minimize2, Maximize2, Loader2, Eye } from "lucide-react";

interface CyrusHumanoidProps {
  module: "vision" | "documents" | "navigation" | "communications" | "systems" | "aerospace" | "trading";
  context?: string;
  onAnalysis?: (response: string) => void;
  compact?: boolean;
}

const modulePrompts: Record<string, string> = {
  vision: "You are CYRUS, a humanoid intelligence engaged in visual analysis. Identify objects, analyze images, describe scenes, and provide insights about what you perceive.",
  documents: "You are CYRUS, a humanoid intelligence engaged in document analysis. Analyze files, extract information, summarize content, identify risks, and generate professional documents.",
  navigation: "You are CYRUS, a humanoid intelligence engaged in navigation and geolocation. Assist with route planning, location analysis, travel estimates, and geographic intelligence.",
  communications: "You are CYRUS, a humanoid intelligence engaged in secure communications. Manage calls, compose messages, and execute communication protocols.",
  systems: "You are CYRUS, a humanoid intelligence engaged in hardware and device control. Manage devices, monitor systems, troubleshoot issues, and execute security operations.",
  aerospace: "You are CYRUS, a humanoid intelligence engaged in UAV/drone operations. Execute flight planning, mission parameters, telemetry analysis, and autonomous operations.",
  trading: "You are CYRUS, a humanoid intelligence engaged in financial markets analysis. Provide technical analysis, trading strategies, risk assessment, and market intelligence.",
};

export function CyrusHumanoid({ module, context, onAnalysis, compact = false }: CyrusHumanoidProps) {
  const [input, setInput] = useState("");
  const [messages, setMessages] = useState<{ role: "user" | "cyrus"; content: string; visual?: { topic: string; category: string; image: string } }[]>([]);
  const [isListening, setIsListening] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isExpanded, setIsExpanded] = useState(!compact);
  const chatEndRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<SpeechRecognition | null>(null);

  const sendMessage = useMutation({
    mutationFn: async (message: string) => {
      const systemContext = `${modulePrompts[module]}\n\nCurrent context: ${context || "No specific context provided."}`;

      const response = await fetch("/api/infer", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ 
          message,
          systemContext,
          module 
        }),
      });

      if (!response.ok) throw new Error("Failed to get response");
      return response.json();
    },
    onSuccess: (data) => {
      const cyrusResponse = data.response || "I apologize, I couldn't process that request.";
      const visual = data.visual?.image ? { topic: data.visual.topic, category: data.visual.category, image: data.visual.image } : undefined;
      setMessages(prev => [...prev, { role: "cyrus", content: cyrusResponse, visual }]);
      onAnalysis?.(cyrusResponse);

      if (!compact) {
        speakResponse(cyrusResponse);
      }
    },
  });

  const speakResponse = async (text: string) => {
    try {
      setIsSpeaking(true);
      const response = await fetch("/api/cyrus/speak", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ text, voice: "nova" }),
      });

      if (response.ok) {
        const audioBlob = await response.blob();
        const audio = new Audio(URL.createObjectURL(audioBlob));
        audio.onended = () => setIsSpeaking(false);
        audio.play();
      } else {
        setIsSpeaking(false);
      }
    } catch {
      setIsSpeaking(false);
    }
  };

  const toggleVoice = () => {
    if (isListening) {
      recognitionRef.current?.stop();
      setIsListening(false);
    } else {
      const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
      if (!SpeechRecognition) return;

      const recognition = new SpeechRecognition();
      recognition.continuous = false;
      recognition.interimResults = false;
      recognition.lang = "en-US";

      recognition.onresult = (event) => {
        const transcript = event.results[0][0].transcript;
        setInput(transcript);
        handleSubmit(transcript);
      };

      recognition.onend = () => setIsListening(false);
      recognition.onerror = () => setIsListening(false);

      recognitionRef.current = recognition;
      recognition.start();
      setIsListening(true);
    }
  };

  const handleSubmit = (text?: string) => {
    const message = text || input.trim();
    if (!message || sendMessage.isPending) return;

    setMessages(prev => [...prev, { role: "user", content: message }]);
    sendMessage.mutate(message);
    setInput("");
  };

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  if (compact && !isExpanded) {
    return (
      <button
        onClick={() => setIsExpanded(true)}
        className="fixed bottom-4 right-4 w-12 h-12 rounded-full overflow-hidden border border-cyan-500/30 shadow-lg shadow-cyan-500/20 hover:scale-105 transition-transform z-50"
      >
        <img src="/images/cyrus-logo.png" alt="CYRUS" className="w-full h-full object-cover" />
      </button>
    );
  }

  return (
    <div className={`bg-[#1c1c1e] rounded-xl border border-[rgba(84,84,88,0.65)] overflow-hidden ${compact ? "fixed bottom-4 right-4 w-80 shadow-2xl z-50" : ""}`}>
      <div className="px-3 py-2 bg-[#2c2c2e] border-b border-[rgba(84,84,88,0.65)] flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className="w-6 h-6 rounded-lg overflow-hidden border border-cyan-500/30 shadow-sm shadow-cyan-500/20">
            <img src="/images/cyrus-logo.png" alt="CYRUS" className="w-full h-full object-cover" />
          </div>
          <span className="text-xs font-semibold">CYRUS HUMANOID</span>
          {isSpeaking && (
            <Volume2 className="w-3 h-3 text-[#0a84ff] animate-pulse" />
          )}
        </div>
        {compact && (
          <button onClick={() => setIsExpanded(false)} className="p-1 text-[rgba(235,235,245,0.4)] hover:text-white">
            <X className="w-4 h-4" />
          </button>
        )}
      </div>

      <div className="h-48 overflow-y-auto p-3 space-y-2">
        {messages.length === 0 ? (
          <div className="h-full flex items-center justify-center text-center">
            <div>
              <div className="w-10 h-10 mx-auto mb-2 rounded-lg overflow-hidden border border-cyan-500/30 shadow-sm shadow-cyan-500/20 opacity-70">
                <img src="/images/cyrus-logo.png" alt="CYRUS" className="w-full h-full object-cover" />
              </div>
              <p className="text-xs text-[rgba(235,235,245,0.4)]">
                Engage CYRUS for {module} operations
              </p>
            </div>
          </div>
        ) : (
          messages.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}>
              <div className={`max-w-[85%] px-3 py-2 rounded-xl text-xs ${
                msg.role === "user" 
                  ? "bg-[#0a84ff] text-white" 
                  : "bg-[#3a3a3c] text-white"
              }`}>
                {msg.content}
                {msg.visual?.image && (
                  <div className="mt-2 rounded-lg overflow-hidden border border-cyan-500/20">
                    <img src={msg.visual.image} alt={`Visual: ${msg.visual.topic}`} className="w-full h-auto" loading="lazy" />
                    <div className="px-2 py-1 bg-[#1a1a2e] text-[10px] text-cyan-400 flex items-center gap-1">
                      <Eye className="w-3 h-3" />
                      <span>{msg.visual.topic} ({msg.visual.category})</span>
                    </div>
                  </div>
                )}
              </div>
            </div>
          ))
        )}
        {sendMessage.isPending && (
          <div className="flex justify-start">
            <div className="bg-[#3a3a3c] rounded-xl px-3 py-2">
              <Loader2 className="w-4 h-4 text-[#0a84ff] animate-spin" />
            </div>
          </div>
        )}
        <div ref={chatEndRef} />
      </div>

      <div className="p-2 border-t border-[rgba(84,84,88,0.65)]">
        <div className="flex items-center gap-2 bg-[rgba(120,120,128,0.2)] rounded-lg px-3 py-2">
          <button
            onClick={toggleVoice}
            className={`p-1 rounded transition-colors ${isListening ? "text-red-400" : "text-[rgba(235,235,245,0.4)] hover:text-white"}`}
          >
            {isListening ? <MicOff className="w-4 h-4" /> : <Mic className="w-4 h-4" />}
          </button>
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && handleSubmit()}
            placeholder="Speak to CYRUS..."
            className="flex-1 bg-transparent text-xs text-white placeholder-[rgba(235,235,245,0.3)] outline-none"
            disabled={sendMessage.isPending}
          />
          <button
            onClick={() => handleSubmit()}
            disabled={!input.trim() || sendMessage.isPending}
            className="p-1 text-[#0a84ff] disabled:opacity-30"
          >
            <Send className="w-4 h-4" />
          </button>
        </div>
      </div>
    </div>
  );
}

server/ingestion/extract.ts.content:
import { detectFile } from "./detect";
import { ensureCompatibleFormat, speechToText } from "../replit_integrations/audio/client";
import { Buffer } from "node:buffer";
import pdfParse from "pdf-parse";
import mammoth from "mammoth";
import fs from "fs/promises";
import os from "os";
import path from "path";
import { execFile } from "child_process";
import { promisify } from "util";
import OpenAI from "openai";

const execFileAsync = promisify(execFile);

const openaiApiKey = process.env.OPENAI_API_KEY || process.env.AI_INTEGRATIONS_OPENAI_API_KEY;
const openaiBaseUrl = process.env.AI_INTEGRATIONS_OPENAI_BASE_URL;
const visionClient =
  openaiApiKey
    ? new OpenAI({ apiKey: openaiApiKey, baseURL: openaiBaseUrl })
    : null;

export interface ExtractionResult {
  text?: string;
  ocrText?: string;
  visionNotes?: string;
  transcript?: string;
  frames?: Array<{ index: number; ocrText?: string; visionNotes?: string }>;
  warnings: string[];
  attempted: string[];
}

async function extractTextDocument(buffer: Buffer, detectedMime?: string): Promise<string> {
  if (detectedMime === "application/pdf") {
    const data = await pdfParse(buffer);
    return data.text || "";
  }
  if (detectedMime && detectedMime.includes("word")) {
    const { value } = await mammoth.extractRawText({ buffer });
    return value || "";
  }
  // Fallback: attempt UTF-8 decode
  return buffer.toString("utf-8");
}

async function extractImageWithVision(buffer: Buffer): Promise<{ ocrText?: string; visionNotes?: string; warnings?: string[] }> {
  const warnings: string[] = [];
  if (!visionClient) {
    warnings.push("Vision not configured (missing OpenAI env); returning placeholder.");
    return { ocrText: "", visionNotes: "Vision unavailable", warnings };
  }
  // OpenAI Vision expects base64 image input
  const b64 = buffer.toString("base64");
  try {
    const resp = await visionClient.chat.completions.create({
      model: "gpt-4o-mini",
      messages: [
        {
          role: "system",
          content:
            "You are an OCR and visual analysis tool. Extract readable text verbatim and describe notable visual elements (objects, layout, stamps, signatures). Return concise OCR text and notes.",
        },
        {
          role: "user",
          content: [
            {
              type: "text",
              text: "Perform OCR and brief visual notes.",
            },
            {
              type: "image_url",
              image_url: { url: `data:image/png;base64,${b64}` },
            },
          ],
        },
      ],
      max_tokens: 500,
    });
    const content = resp.choices[0]?.message?.content || "";
    // Heuristic: split into OCR vs notes
    return { ocrText: content, visionNotes: "Vision/OCR from model", warnings };
  } catch (err: any) {
    warnings.push(`Vision call failed: ${err?.message || err}`);
    return { ocrText: "", visionNotes: "Vision failed", warnings };
  }
}

async function extractVideoFrame(buffer: Buffer, seconds: number): Promise<Buffer | null> {
  const tmpDir = os.tmpdir();
  const inputPath = path.join(tmpDir, `vid-${Date.now()}.bin`);
  const outputPath = path.join(tmpDir, `frame-${Date.now()}.png`);
  await fs.writeFile(inputPath, buffer);
  try {
    await execFileAsync("ffmpeg", [
      "-i",
      inputPath,
      "-ss",
      String(seconds),
      "-vframes",
      "1",
      "-y",
      outputPath,
    ]);
    const frame = await fs.readFile(outputPath);
    return frame;
  } catch (err) {
    return null;
  } finally {
    await fs.unlink(inputPath).catch(() => {});
    await fs.unlink(outputPath).catch(() => {});
  }
}

export async function extractFile(buffer: Buffer, declaredMime?: string): Promise<ExtractionResult> {
  const det = await detectFile(buffer, declaredMime);
  const warnings: string[] = [];
  const attempted: string[] = [];

  const detected = det.detectedMime || det.declaredMime || "application/octet-stream";

  // Branch by detected MIME
  if (detected.startsWith("text/") || detected === "application/pdf" || detected.includes("word")) {
    attempted.push("text-extract");
    try {
      const text = await extractTextDocument(buffer, detected);
      if (text && text.trim().length > 0) {
        return { text, warnings, attempted };
      }
      warnings.push("Primary text extraction returned empty; attempting OCR if applicable.");
    } catch (err: any) {
      warnings.push(`Text extraction failed: ${err?.message || err}`);
    }
  }

  if (detected.startsWith("image/") || detected === "application/pdf") {
    attempted.push("vision-ocr");
    const vis = await extractImageWithVision(buffer);
    warnings.push(...(vis.warnings || []));
    return { ocrText: vis.ocrText, visionNotes: vis.visionNotes, warnings, attempted };
  }

  if (detected.startsWith("audio/")) {
    attempted.push("audio-transcribe");
    try {
      const { buffer: wav, format } = await ensureCompatibleFormat(buffer);
      const transcript = await speechToText(wav, format);
      return { transcript, warnings, attempted };
    } catch (err: any) {
      warnings.push(`Audio transcription failed: ${err?.message || err}`);
      return { warnings, attempted };
    }
  }

  if (detected.startsWith("video/")) {
    attempted.push("video-audio-transcribe");
    warnings.push("Video frame OCR partial: sampling a single frame.");
    try {
      const { buffer: wav, format } = await ensureCompatibleFormat(buffer);
      const transcript = await speechToText(wav, format);
      // Sample a frame at 1s for OCR (placeholder)
      const frame = await extractVideoFrame(buffer, 1);
      let frameOcr = "";
      if (frame) {
        const vis = await extractImageWithVision(frame);
        warnings.push(...(vis.warnings || []));
        frameOcr = vis.ocrText || "";
      } else {
        warnings.push("Frame sampling failed or ffmpeg missing.");
      }
      return { transcript, frames: frameOcr ? [{ index: 1, ocrText: frameOcr }] : [], warnings, attempted };
    } catch (err: any) {
      warnings.push(`Video audio transcription failed: ${err?.message || err}`);
      return { warnings, attempted };
    }
  }

  // Unknown / fallback
  warnings.push("Unknown format; minimal inspection only.");
  return { warnings, attempted: [...attempted, "unknown-minimal"] };
}

server/ai/interactive/security-encryptio.content:
import { createCipheriv, createDecipheriv, randomBytes, createHash, pbkdf2Sync, timingSafeEqual, CipherGCM, DecipherGCM } from "crypto";

interface EncryptedData {
  iv: string;
  encrypted: string;
  authTag?: string;
  algorithm: string;
  keyId: string;
}

interface SecureKey {
  id: string;
  key: Buffer;
  algorithm: string;
  createdAt: number;
  expiresAt?: number;
  usageCount: number;
}

interface AuditLogEntry {
  id: string;
  timestamp: number;
  action: string;
  userId?: string;
  resourceType: string;
  resourceId: string;
  ipAddress?: string;
  success: boolean;
  details?: Record<string, any>;
}

interface AccessControl {
  userId: string;
  role: "admin" | "operator" | "viewer" | "patient" | "researcher";
  permissions: string[];
  restrictions: string[];
  mfaEnabled: boolean;
  lastAccess: number;
}

interface DataClassification {
  level: "public" | "internal" | "confidential" | "restricted" | "top_secret";
  category: "medical" | "personal" | "financial" | "research" | "operational";
  retentionDays: number;
  encryptionRequired: boolean;
  auditRequired: boolean;
}

interface IntegrityCheck {
  hash: string;
  algorithm: string;
  timestamp: number;
  verified: boolean;
}

class SecurityEncryptionModule {
  private keys: Map<string, SecureKey> = new Map();
  private auditLog: AuditLogEntry[] = [];
  private accessControls: Map<string, AccessControl> = new Map();
  private dataClassifications: Map<string, DataClassification> = new Map();
  private masterKey: Buffer;
  private defaultAlgorithm = "aes-256-gcm";

  constructor() {
    console.log("[Security Module] Initializing encryption and security system");
    this.masterKey = this.deriveMasterKey();
    this.initializeDefaultClassifications();
    console.log("[Security Module] AES-256-GCM encryption ready");
  }

  private deriveMasterKey(): Buffer {
    const secret = process.env.ENCRYPTION_SECRET || "cyrus-secure-default-key-change-in-production";
    const salt = process.env.ENCRYPTION_SALT || "cyrus-salt-v1";
    return pbkdf2Sync(secret, salt, 100000, 32, "sha512");
  }

  private initializeDefaultClassifications(): void {
    const classifications: Array<[string, DataClassification]> = [
      ["medical_records", { level: "restricted", category: "medical", retentionDays: 365 * 7, encryptionRequired: true, auditRequired: true }],
      ["patient_data", { level: "confidential", category: "personal", retentionDays: 365 * 5, encryptionRequired: true, auditRequired: true }],
      ["research_data", { level: "confidential", category: "research", retentionDays: 365 * 10, encryptionRequired: true, auditRequired: true }],
      ["operational_logs", { level: "internal", category: "operational", retentionDays: 365, encryptionRequired: false, auditRequired: true }],
      ["public_info", { level: "public", category: "operational", retentionDays: 365 * 3, encryptionRequired: false, auditRequired: false }]
    ];

    classifications.forEach(([id, classification]) => {
      this.dataClassifications.set(id, classification);
    });
  }

  generateKey(algorithm: string = this.defaultAlgorithm): SecureKey {
    const keyLength = algorithm.includes("256") ? 32 : 16;
    const key: SecureKey = {
      id: `key_${Date.now()}_${randomBytes(4).toString("hex")}`,
      key: randomBytes(keyLength),
      algorithm,
      createdAt: Date.now(),
      usageCount: 0
    };
    this.keys.set(key.id, key);
    return key;
  }

  encrypt(data: string | Buffer, keyId?: string): EncryptedData {
    let key: SecureKey;

    if (keyId && this.keys.has(keyId)) {
      key = this.keys.get(keyId)!;
    } else {
      key = this.generateKey();
    }

    const iv = randomBytes(16);
    const cipher = createCipheriv(key.algorithm, key.key, iv) as CipherGCM;

    const dataBuffer = typeof data === "string" ? Buffer.from(data, "utf8") : data;
    const encrypted = Buffer.concat([cipher.update(dataBuffer), cipher.final()]);
    const authTag = cipher.getAuthTag();

    key.usageCount++;
    this.keys.set(key.id, key);

    return {
      iv: iv.toString("hex"),
      encrypted: encrypted.toString("hex"),
      authTag: authTag.toString("hex"),
      algorithm: key.algorithm,
      keyId: key.id
    };
  }

  decrypt(encryptedData: EncryptedData): Buffer {
    const key = this.keys.get(encryptedData.keyId);
    if (!key) {
      throw new Error("Decryption key not found");
    }

    const iv = Buffer.from(encryptedData.iv, "hex");
    const encrypted = Buffer.from(encryptedData.encrypted, "hex");
    const decipher = createDecipheriv(key.algorithm, key.key, iv) as DecipherGCM;

    if (encryptedData.authTag) {
      decipher.setAuthTag(Buffer.from(encryptedData.authTag, "hex"));
    }

    return Buffer.concat([decipher.update(encrypted), decipher.final()]);
  }

  decryptToString(encryptedData: EncryptedData): string {
    return this.decrypt(encryptedData).toString("utf8");
  }

  hash(data: string | Buffer, algorithm: string = "sha256"): string {
    const hash = createHash(algorithm);
    hash.update(data);
    return hash.digest("hex");
  }

  verifyHash(data: string | Buffer, expectedHash: string, algorithm: string = "sha256"): boolean {
    const actualHash = this.hash(data, algorithm);
    try {
      return timingSafeEqual(Buffer.from(actualHash, "hex"), Buffer.from(expectedHash, "hex"));
    } catch {
      return false;
    }
  }

  computeIntegrity(data: string | Buffer): IntegrityCheck {
    const algorithm = "sha256";
    return {
      hash: this.hash(data, algorithm),
      algorithm,
      timestamp: Date.now(),
      verified: true
    };
  }

  verifyIntegrity(data: string | Buffer, check: IntegrityCheck): boolean {
    return this.verifyHash(data, check.hash, check.algorithm);
  }

  registerUser(userId: string, role: AccessControl["role"]): AccessControl {
    const permissions = this.getDefaultPermissions(role);
    const control: AccessControl = {
      userId,
      role,
      permissions,
      restrictions: [],
      mfaEnabled: role === "admin",
      lastAccess: Date.now()
    };
    this.accessControls.set(userId, control);
    return control;
  }

  private getDefaultPermissions(role: AccessControl["role"]): string[] {
    const permissionMap: Record<string, string[]> = {
      admin: ["read", "write", "delete", "admin", "audit", "encrypt", "decrypt"],
      operator: ["read", "write", "encrypt", "decrypt", "execute"],
      viewer: ["read"],
      patient: ["read:own", "write:own"],
      researcher: ["read", "write", "analyze", "export"]
    };
    return permissionMap[role] || ["read"];
  }

  checkPermission(userId: string, permission: string, resourceType?: string): boolean {
    const control = this.accessControls.get(userId);
    if (!control) return false;

    if (control.restrictions.includes(permission)) return false;

    if (control.permissions.includes(permission)) return true;
    if (permission.includes(":own") && control.permissions.includes(permission.split(":")[0] + ":own")) return true;

    return false;
  }

  updateLastAccess(userId: string): void {
    const control = this.accessControls.get(userId);
    if (control) {
      control.lastAccess = Date.now();
      this.accessControls.set(userId, control);
    }
  }

  logAudit(entry: Omit<AuditLogEntry, "id" | "timestamp">): void {
    const auditEntry: AuditLogEntry = {
      ...entry,
      id: `audit_${Date.now()}_${randomBytes(4).toString("hex")}`,
      timestamp: Date.now()
    };
    this.auditLog.push(auditEntry);

    if (this.auditLog.length > 10000) {
      this.auditLog = this.auditLog.slice(-5000);
    }
  }

  getAuditLog(filters?: {
    userId?: string;
    resourceType?: string;
    startTime?: number;
    endTime?: number;
    success?: boolean;
  }): AuditLogEntry[] {
    let logs = [...this.auditLog];

    if (filters) {
      if (filters.userId) logs = logs.filter(l => l.userId === filters.userId);
      if (filters.resourceType) logs = logs.filter(l => l.resourceType === filters.resourceType);
      if (filters.startTime) logs = logs.filter(l => l.timestamp >= filters.startTime!);
      if (filters.endTime) logs = logs.filter(l => l.timestamp <= filters.endTime!);
      if (filters.success !== undefined) logs = logs.filter(l => l.success === filters.success);
    }

    return logs;
  }

  classifyData(resourceId: string, classification: DataClassification): void {
    this.dataClassifications.set(resourceId, classification);
  }

  getClassification(resourceId: string): DataClassification | undefined {
    return this.dataClassifications.get(resourceId);
  }

  secureDelete(data: Buffer | string): void {
    if (Buffer.isBuffer(data)) {
      data.fill(0);
    }
  }

  rotateKey(oldKeyId: string): SecureKey | null {
    const oldKey = this.keys.get(oldKeyId);
    if (!oldKey) return null;

    const newKey = this.generateKey(oldKey.algorithm);

    this.logAudit({
      action: "key_rotation",
      resourceType: "encryption_key",
      resourceId: oldKeyId,
      success: true,
      details: { newKeyId: newKey.id }
    });

    return newKey;
  }

  exportKey(keyId: string, wrapperKeyId: string): EncryptedData | null {
    const key = this.keys.get(keyId);
    if (!key) return null;

    return this.encrypt(key.key, wrapperKeyId);
  }

  generateSecureToken(length: number = 32): string {
    return randomBytes(length).toString("hex");
  }

  validateToken(token: string, expectedToken: string): boolean {
    try {
      return timingSafeEqual(Buffer.from(token), Buffer.from(expectedToken));
    } catch {
      return false;
    }
  }

  getStatus(): {
    operational: boolean;
    keys: number;
    auditEntries: number;
    users: number;
    encryptionAlgorithm: string;
  } {
    return {
      operational: true,
      keys: this.keys.size,
      auditEntries: this.auditLog.length,
      users: this.accessControls.size,
      encryptionAlgorithm: this.defaultAlgorithm
    };
  }
}

export const securityEncryption = new SecurityEncryptionModule();

