                className="w-full bg-[#2c2c2e] border border-[rgba(84,84,88,0.65)] rounded-lg px-4 py-3 text-white placeholder-[rgba(235,235,245,0.3)] min-h-[80px] text-sm"
              />
              <button
                onClick={() => analyzeMutation.mutate()}
                disabled={analyzeMutation.isPending}
                className="mt-4 w-full bg-gradient-to-r from-red-500 to-rose-600 hover:from-red-600 hover:to-rose-700 text-white font-semibold py-3 rounded-lg flex items-center justify-center gap-2 transition-all disabled:opacity-50"
              >
                {analyzeMutation.isPending ? (
                  <>
                    <Loader2 className="w-5 h-5 animate-spin" />
                    Analyzing...
                  </>
                ) : (
                  <>
                    <Brain className="w-5 h-5" />
                    Run AI Diagnosis
                  </>
                )}
              </button>
            </div>

            {diagnosis && (
              <>
                <div className={`border rounded-xl p-5 ${getUrgencyColor(diagnosis.urgency)}`}>
                  <div className="flex items-center gap-3 mb-3">
                    {diagnosis.urgency === "critical" || diagnosis.urgency === "high" ? (
                      <AlertTriangle className="w-6 h-6" />
                    ) : (
                      <CheckCircle2 className="w-6 h-6" />
                    )}
                    <div>
                      <h2 className="text-lg font-semibold capitalize">{diagnosis.urgency} Priority</h2>
                      <p className="text-sm opacity-80">Quantified Analysis</p>
                    </div>
                  </div>
                  <p className="text-sm whitespace-pre-line">{diagnosis.summary}</p>
                </div>

                <div className="bg-[#1c1c1e] border border-[rgba(84,84,88,0.65)] rounded-xl p-5">
                  <h2 className="text-lg font-semibold mb-4">Conditions</h2>
                  <div className="space-y-3">
                    {diagnosis.conditions.map((condition, i) => (
                      <div key={i} className="bg-[#2c2c2e] rounded-lg p-3">
                        <div className="flex items-center justify-between mb-2">
                          <span className="font-medium text-sm">{condition.name}</span>
                          <span className={`text-xs px-2 py-0.5 rounded-full ${
                            condition.severity === "high" ? "bg-red-500/20 text-red-400" :
                            condition.severity === "medium" ? "bg-amber-500/20 text-amber-400" :
                            "bg-emerald-500/20 text-emerald-400"
                          }`}>
                            {condition.severity}
                          </span>
                        </div>
                        <div className="flex items-center gap-2">
                          <div className="flex-1 h-1.5 bg-[#1c1c1e] rounded-full overflow-hidden">
                            <div
                              className="h-full bg-gradient-to-r from-blue-500 to-cyan-500"
                              style={{ width: `${condition.probability * 100}%` }}
                            />
                          </div>
                          <span className="text-xs text-[rgba(235,235,245,0.5)]">
                            {Math.round(condition.probability * 100)}%
                          </span>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>

                <div className="bg-[#1c1c1e] border border-[rgba(84,84,88,0.65)] rounded-xl p-5">
                  <h2 className="text-lg font-semibold mb-4">Recommendations</h2>
                  <ul className="space-y-2">
                    {diagnosis.recommendations.map((rec, i) => (
                      <li key={i} className="flex items-start gap-2 text-sm text-[rgba(235,235,245,0.8)]">
                        <CheckCircle2 className="w-4 h-4 text-emerald-400 mt-0.5 shrink-0" />
                        {rec}
                      </li>
                    ))}
                  </ul>
                </div>
              </>
            )}
          </div>
        </div>
      </div>

      {showScanModal && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-[#1c1c1e] border border-[rgba(84,84,88,0.65)] rounded-2xl w-full max-w-md overflow-hidden">
            <div className="p-6 border-b border-[rgba(84,84,88,0.65)]">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className={`w-10 h-10 rounded-full flex items-center justify-center ${isScanning ? "bg-cyan-500/20" : "bg-[#2c2c2e]"}`}>
                    <Bluetooth className={`w-5 h-5 ${isScanning ? "text-cyan-400 animate-pulse" : "text-[rgba(235,235,245,0.6)]"}`} />
                  </div>
                  <div>
                    <h2 className="text-lg font-semibold">Scan Devices</h2>
                    <p className="text-sm text-[rgba(235,235,245,0.5)]">
                      {isScanning ? "Scanning nearby..." : `${discoveredDevices.length} devices found`}
                    </p>
                  </div>
                </div>
                <button
                  onClick={() => setShowScanModal(false)}
                  className="text-[rgba(235,235,245,0.5)] hover:text-white transition-colors"
                >
                  ✕
                </button>
              </div>
            </div>

            <div className="p-4 max-h-80 overflow-y-auto">
              {isScanning && discoveredDevices.length === 0 ? (
                <div className="flex flex-col items-center justify-center py-12">
                  <div className="relative">
                    <div className="w-16 h-16 rounded-full border-2 border-cyan-500/30 animate-ping absolute inset-0" />
                    <div className="w-16 h-16 rounded-full border-2 border-cyan-500/50 animate-pulse absolute inset-0" style={{ animationDelay: "0.5s" }} />
                    <div className="w-16 h-16 rounded-full bg-cyan-500/20 flex items-center justify-center relative">
                      <Bluetooth className="w-8 h-8 text-cyan-400" />
                    </div>
                  </div>
                  <p className="text-sm text-[rgba(235,235,245,0.5)] mt-4">Scanning for nearby devices...</p>
                </div>
              ) : (
                <div className="space-y-2">
                  {discoveredDevices.map((device) => (
                    <div
                      key={device.id}
                      className={`p-4 rounded-xl border transition-all ${
                        device.paired 
                          ? "bg-emerald-500/10 border-emerald-500/30" 
                          : "bg-[#2c2c2e] border-[rgba(84,84,88,0.65)] hover:border-cyan-500/30"
                      }`}
                    >
                      <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                          <div className={`w-10 h-10 rounded-lg flex items-center justify-center ${
                            device.type === "watch" ? "bg-cyan-500/20" : "bg-[#1c1c1e]"
                          }`}>
                            {device.type === "watch" ? (
                              <Watch className="w-5 h-5 text-cyan-400" />
                            ) : device.type === "audio" ? (
                              <Activity className="w-5 h-5 text-purple-400" />
                            ) : (
                              <Bluetooth className="w-5 h-5 text-[rgba(235,235,245,0.4)]" />
                            )}
                          </div>
                          <div>
                            <p className="font-medium text-sm">{device.name}</p>
                            <div className="flex items-center gap-2 mt-0.5">
                              <Signal className={`w-3 h-3 ${device.signal > 70 ? "text-emerald-400" : device.signal > 40 ? "text-amber-400" : "text-red-400"}`} />
                              <span className="text-xs text-[rgba(235,235,245,0.4)]">{device.signal}%</span>
                            </div>
                          </div>
                        </div>
                        {device.paired ? (
                          <span className="text-xs text-emerald-400 flex items-center gap-1">
                            <BluetoothConnected className="w-3 h-3" />
                            Connected
                          </span>
                        ) : pairingDevice === device.id ? (
                          <div className="flex items-center gap-2">
                            <Loader2 className="w-4 h-4 text-cyan-400 animate-spin" />
                            <span className="text-xs text-cyan-400">Pairing...</span>
                          </div>
                        ) : (
                          <button
                            onClick={() => pairDevice(device.id)}
                            disabled={!!pairingDevice}
                            className="px-4 py-1.5 bg-cyan-500 hover:bg-cyan-600 text-white text-xs font-medium rounded-lg transition-colors disabled:opacity-50"
                          >
                            Connect
                          </button>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div className="p-4 border-t border-[rgba(84,84,88,0.65)] flex items-center justify-between">
              <button
                onClick={startBluetoothScan}
                disabled={isScanning}
                className="flex items-center gap-2 text-sm text-cyan-400 disabled:opacity-50"
              >
                <RefreshCw className={`w-4 h-4 ${isScanning ? "animate-spin" : ""}`} />
                {isScanning ? "Scanning..." : "Scan Again"}
              </button>
              <button
                onClick={() => setShowScanModal(false)}
                className="px-4 py-2 bg-[#2c2c2e] hover:bg-[#3c3c3e] text-white text-sm font-medium rounded-lg transition-colors"
              >
                Done
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

client/src/hooks/useDeviceControl.ts.content:
import { useState } from "react";
import { useMutation, useQuery } from "@tanstack/react-query";

export type DeviceAction =
  | "open_app"
  | "focus_app"
  | "keystroke"
  | "text"
  | "pointer_move"
  | "pointer_click"
  | "pointer_drag"
  | "scroll"
  | "shortcut"
  | "screenshot";

export interface DeviceCommand {
  action: DeviceAction;
  appName?: string;
  bundleId?: string;
  text?: string;
  keys?: string[];
  x?: number;
  y?: number;
  dx?: number;
  dy?: number;
  button?: "left" | "right" | "middle";
  shortcut?: string[];
  dryRun?: boolean;
  confirmToken?: string;
}

export interface DeviceResult {
  success: boolean;
  detail: string;
  platform: string;
  dryRun: boolean;
  confirmToken?: string;
}

export interface DeviceStatus {
  enabled: boolean;
  platform: string;
  allowedApps: string[];
  dryRunDefault: boolean;
}

export function useDeviceControl() {
  const [lastResult, setLastResult] = useState<DeviceResult | null>(null);
  const [pendingConfirm, setPendingConfirm] = useState<{
    command: DeviceCommand;
    token: string;
  } | null>(null);

  const statusQuery = useQuery<DeviceStatus>({
    queryKey: ["/api/device/status"],
    queryFn: async () => {
      const res = await fetch("/api/device/status");
      if (!res.ok) throw new Error("Failed to fetch device status");
      return res.json();
    },
  });

  const executeCommand = useMutation({
    mutationFn: async (command: DeviceCommand) => {
      const res = await fetch("/api/device/execute", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(command),
      });
      if (!res.ok) {
        const error = await res.json();
        throw new Error(error.error || "Command execution failed");
      }
      const result = await res.json();
      setLastResult(result);
      if (result.confirmToken) {
        setPendingConfirm({ command, token: result.confirmToken });
      }
      return result;
    },
  });

  const confirmCommand = useMutation({
    mutationFn: async () => {
      if (!pendingConfirm) throw new Error("No pending confirmation");
      const res = await fetch("/api/device/execute", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ...pendingConfirm.command,
          confirmToken: pendingConfirm.token,
          dryRun: false,
        }),
      });
      if (!res.ok) {
        const error = await res.json();
        throw new Error(error.error || "Command execution failed");
      }
      const result = await res.json();
      setLastResult(result);
      setPendingConfirm(null);
      return result;
    },
  });

  const cancelConfirm = () => {
    setPendingConfirm(null);
  };

  const openApp = (appName: string, dryRun = true) =>
    executeCommand.mutate({ action: "open_app", appName, dryRun });

  const focusApp = (appName: string, dryRun = true) =>
    executeCommand.mutate({ action: "focus_app", appName, dryRun });

  const typeText = (text: string, dryRun = true) =>
    executeCommand.mutate({ action: "text", text, dryRun });

  const pressKeys = (keys: string[], dryRun = true) =>
    executeCommand.mutate({ action: "keystroke", keys, dryRun });

  const shortcut = (keys: string[], dryRun = true) =>
    executeCommand.mutate({ action: "shortcut", shortcut: keys, dryRun });

  const moveMouse = (x: number, y: number, dryRun = true) =>
    executeCommand.mutate({ action: "pointer_move", x, y, dryRun });

  const click = (
    x: number,
    y: number,
    button: "left" | "right" | "middle" = "left",
    dryRun = true
  ) => executeCommand.mutate({ action: "pointer_click", x, y, button, dryRun });

  const drag = (
    x: number,
    y: number,
    dx: number,
    dy: number,
    dryRun = true
  ) => executeCommand.mutate({ action: "pointer_drag", x, y, dx, dy, dryRun });

  const scroll = (dx: number, dy: number, dryRun = true) =>
    executeCommand.mutate({ action: "scroll", dx, dy, dryRun });

  const takeScreenshot = (dryRun = true) =>
    executeCommand.mutate({ action: "screenshot", dryRun });

  return {
    status: statusQuery.data,
    lastResult,
    pendingConfirm,
    isExecuting: executeCommand.isPending || confirmCommand.isPending,
    isLoading: statusQuery.isLoading,
    executeCommand,
    confirmCommand,
    cancelConfirm,
    openApp,
    focusApp,
    typeText,
    pressKeys,
    shortcut,
    moveMouse,
    click,
    drag,
    scroll,
    takeScreenshot,
  };
}

client/src/hooks/use-auth.ts.content:
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import type { User } from "@shared/models/auth";

async function fetchUser(): Promise<User | null> {
  const response = await fetch("/api/auth/user", {
    credentials: "include",
  });

  if (response.status === 401) {
    return null;
  }

  if (!response.ok) {
    throw new Error(`${response.status}: ${response.statusText}`);
  }

  return response.json();
}

async function logout(): Promise<void> {
  window.location.href = "/api/logout";
}

export function useAuth() {
  const queryClient = useQueryClient();
  const { data: user, isLoading } = useQuery<User | null>({
    queryKey: ["/api/auth/user"],
    queryFn: fetchUser,
    retry: false,
    staleTime: 1000 * 60 * 5, // 5 minutes
  });

  const logoutMutation = useMutation({
    mutationFn: logout,
    onSuccess: () => {
      queryClient.setQueryData(["/api/auth/user"], null);
    },
  });

  return {
    user,
    isLoading,
    isAuthenticated: !!user,
    logout: logoutMutation.mutate,
    isLoggingOut: logoutMutation.isPending,
  };
}

client/src/hooks/useWakeWord.ts.content:
import { useState, useRef, useCallback, useEffect } from "react";

export interface WakeWordConfig {
  wakeWords: string[];
  sensitivity: number;
  silenceTimeout: number;
  autoRestart: boolean;
  onWakeWordDetected?: (transcript: string) => void;
  onCommand?: (command: string) => void;
  onListeningChange?: (isListening: boolean) => void;
  onError?: (error: string) => void;
}

const defaultConfig: WakeWordConfig = {
  wakeWords: ["cyrus", "cyras", "cyprus", "sirus", "syrus", "hey cyrus", "okay cyrus", "ok cyrus"],
  sensitivity: 0.6,
  silenceTimeout: 2000,
  autoRestart: true,
};

export function useWakeWord(config: Partial<WakeWordConfig> = {}) {
  const mergedConfig = { ...defaultConfig, ...config };

  const [isListening, setIsListening] = useState(false);
  const [isActivated, setIsActivated] = useState(false);
  const [lastTranscript, setLastTranscript] = useState("");
  const [isProcessing, setIsProcessing] = useState(false);

  const recognitionRef = useRef<SpeechRecognition | null>(null);
  const silenceTimerRef = useRef<NodeJS.Timeout | null>(null);
  const commandBufferRef = useRef<string>("");
  const isActivatedRef = useRef(false);
  const isListeningRef = useRef(false);
  const isStoppingRef = useRef(false);
  const restartTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  const clearSilenceTimer = useCallback(() => {
    if (silenceTimerRef.current) {
      clearTimeout(silenceTimerRef.current);
      silenceTimerRef.current = null;
    }
  }, []);

  const checkForWakeWord = useCallback((transcript: string): boolean => {
    const normalizedTranscript = transcript.toLowerCase().trim();

    for (const wakeWord of mergedConfig.wakeWords) {
      if (normalizedTranscript.includes(wakeWord.toLowerCase())) {
        return true;
      }
    }

    const phoneticVariations = [
      /\bcy\s*r[uo]s\b/i,
      /\bsai\s*r[uo]s\b/i,
      /\bsi\s*r[uo]s\b/i,
      /\bcyp\s*r[uo]s\b/i,
      /\bsyr\s*[uo]s\b/i,
    ];

    for (const pattern of phoneticVariations) {
      if (pattern.test(normalizedTranscript)) {
        return true;
      }
    }

    return false;
  }, [mergedConfig.wakeWords]);

  const extractCommand = useCallback((transcript: string): string => {
    const normalizedTranscript = transcript.toLowerCase();

    for (const wakeWord of mergedConfig.wakeWords) {
      const wakeWordLower = wakeWord.toLowerCase();
      const index = normalizedTranscript.indexOf(wakeWordLower);
      if (index !== -1) {
        const afterWakeWord = transcript.slice(index + wakeWord.length).trim();
        if (afterWakeWord.length > 0) {
          return afterWakeWord;
        }
      }
    }

    return transcript;
  }, [mergedConfig.wakeWords]);

  const startListening = useCallback(() => {
    if (isStoppingRef.current || isListeningRef.current) {
      return;
    }

    if (recognitionRef.current) {
      try {
        recognitionRef.current.abort();
      } catch {}
      recognitionRef.current = null;
    }

    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SpeechRecognition) {
      mergedConfig.onError?.("Speech recognition not supported in this browser");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.continuous = true;
    recognition.interimResults = true;
    recognition.lang = "en-US";
    (recognition as any).maxAlternatives = 3;

    recognition.onstart = () => {
      isListeningRef.current = true;
      setIsListening(true);
      mergedConfig.onListeningChange?.(true);
      console.log("[WakeWord] Listening started - waiting for 'CYRUS'...");
    };

    recognition.onresult = (event) => {
      clearSilenceTimer();

      let finalTranscript = "";
      let interimTranscript = "";

      for (let i = event.resultIndex; i < event.results.length; i++) {
        const result = event.results[i];
        const transcript = result[0].transcript;

        if (result.isFinal) {
          finalTranscript += transcript;
        } else {
          interimTranscript += transcript;
        }
      }

      const currentTranscript = finalTranscript || interimTranscript;
      setLastTranscript(currentTranscript);

      if (!isActivatedRef.current) {
        if (checkForWakeWord(currentTranscript)) {
          console.log("[WakeWord] Wake word detected:", currentTranscript);
          isActivatedRef.current = true;
          setIsActivated(true);
          mergedConfig.onWakeWordDetected?.(currentTranscript);

          const command = extractCommand(currentTranscript);
          if (command && command.trim().length > 0) {
            commandBufferRef.current = command.trim();
          }

          silenceTimerRef.current = setTimeout(() => {
            if (commandBufferRef.current.length > 0) {
              const fullCommand = commandBufferRef.current.trim();
              console.log("[WakeWord] Command captured:", fullCommand);
              setIsProcessing(true);
              mergedConfig.onCommand?.(fullCommand);

              commandBufferRef.current = "";
              isActivatedRef.current = false;
              setIsActivated(false);
              setIsProcessing(false);
            } else {
              console.log("[WakeWord] No command after wake word, resetting...");
              isActivatedRef.current = false;
              setIsActivated(false);
            }
          }, mergedConfig.silenceTimeout);
        }
      } else {
        if (finalTranscript) {
          const cleanedFinal = extractCommand(finalTranscript).trim();
          if (cleanedFinal && !commandBufferRef.current.includes(cleanedFinal)) {
            commandBufferRef.current = (commandBufferRef.current + " " + cleanedFinal).trim();
          }
        }

        clearSilenceTimer();
        silenceTimerRef.current = setTimeout(() => {
          if (commandBufferRef.current.trim().length > 0) {
            const fullCommand = commandBufferRef.current.trim();
            console.log("[WakeWord] Command captured:", fullCommand);
            setIsProcessing(true);
            mergedConfig.onCommand?.(fullCommand);

            commandBufferRef.current = "";
            isActivatedRef.current = false;
            setIsActivated(false);
            setIsProcessing(false);
          }
        }, mergedConfig.silenceTimeout);
      }
    };

    recognition.onerror = (event) => {
      console.error("[WakeWord] Recognition error:", event.error);

      if (event.error === "not-allowed") {
        mergedConfig.onError?.("Microphone access denied. Please allow microphone access.");
        isListeningRef.current = false;
        setIsListening(false);
        mergedConfig.onListeningChange?.(false);
        return;
      }

      if (event.error === "aborted") {
        return;
      }

      if (event.error === "no-speech" || event.error === "audio-capture" || event.error === "network") {
        if (mergedConfig.autoRestart && isListeningRef.current && !isStoppingRef.current) {
          restartTimeoutRef.current = setTimeout(() => {
            if (isListeningRef.current && !isStoppingRef.current) {
              recognitionRef.current = null;
              startListening();
            }
          }, 500);
        }
      }
    };

    recognition.onend = () => {
      console.log("[WakeWord] Recognition ended");

      if (mergedConfig.autoRestart && isListeningRef.current && !isStoppingRef.current) {
        restartTimeoutRef.current = setTimeout(() => {
          if (isListeningRef.current && !isStoppingRef.current) {
            recognitionRef.current = null;
            startListening();
          }
        }, 300);
      } else {
        isListeningRef.current = false;
        setIsListening(false);
        mergedConfig.onListeningChange?.(false);
      }
    };

    recognitionRef.current = recognition;

    try {
      recognition.start();
    } catch (error) {
      console.error("[WakeWord] Failed to start recognition:", error);
      mergedConfig.onError?.("Failed to start speech recognition");
    }
  }, [checkForWakeWord, extractCommand, clearSilenceTimer, mergedConfig, isListening]);

  const stopListening = useCallback(() => {
    isStoppingRef.current = true;
    clearSilenceTimer();

    if (restartTimeoutRef.current) {
      clearTimeout(restartTimeoutRef.current);
      restartTimeoutRef.current = null;
    }

    if (recognitionRef.current) {
      try {
        recognitionRef.current.abort();
      } catch {}
      recognitionRef.current = null;
    }

    isListeningRef.current = false;
    setIsListening(false);
    setIsActivated(false);
    isActivatedRef.current = false;
    commandBufferRef.current = "";
    mergedConfig.onListeningChange?.(false);

    setTimeout(() => {
      isStoppingRef.current = false;
    }, 100);

    console.log("[WakeWord] Listening stopped");
  }, [clearSilenceTimer, mergedConfig]);

  const toggleListening = useCallback(() => {
    if (isListening) {
      stopListening();
    } else {
      startListening();
    }
  }, [isListening, startListening, stopListening]);

  const resetActivation = useCallback(() => {
    isActivatedRef.current = false;
    setIsActivated(false);
    commandBufferRef.current = "";
    clearSilenceTimer();
  }, [clearSilenceTimer]);

  useEffect(() => {
    return () => {
      stopListening();
    };
  }, [stopListening]);

  return {
    isListening,
    isActivated,
    isProcessing,
    lastTranscript,
    startListening,
    stopListening,
    toggleListening,
    resetActivation,
  };
}

