        sys.path.insert(0, nexus_path)
        from quantum_intelligence_nexus import QuantumIntelligenceNexus
        NEXUS_AVAILABLE = True
    else:
        NEXUS_AVAILABLE = False
except ImportError:
    NEXUS_AVAILABLE = False

try:
    from quantum_visual import MultiModalResponseGenerator
