          {uploadedFiles.length === 0 ? (
            <div 
              className="flex-1 border border-dashed border-[rgba(84,84,88,0.65)] rounded-xl flex flex-col items-center justify-center cursor-pointer hover:border-[#0a84ff] transition-colors"
              onClick={() => fileInputRef.current?.click()}
            >
              <Upload className="w-6 h-6 text-[rgba(235,235,245,0.3)] mb-2" />
              <p className="text-xs text-[rgba(235,235,245,0.4)]">Drop files here</p>
            </div>
          ) : (
            <div className="flex-1 overflow-auto space-y-2">
              {uploadedFiles.map((file, i) => (
                <div key={i} className="flex items-center gap-2 p-3 bg-[#2c2c2e] rounded-lg">
                  <div className="w-8 h-8 bg-[rgba(120,120,128,0.2)] rounded-lg flex items-center justify-center">
                    <FileText className="w-4 h-4 text-[#0a84ff]" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-xs text-white truncate">{file.name}</p>
                    <p className="text-[10px] text-[rgba(235,235,245,0.4)]">{file.size}</p>
                  </div>
                  <button
                    onClick={() => setUploadedFiles(prev => prev.filter((_, idx) => idx !== i))}
                    className="p-1 text-[rgba(235,235,245,0.4)] hover:text-[#ff453a] rounded transition-colors"
                  >
                    <X className="w-4 h-4" />
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* CYRUS Vision Panel - Lower Section (Live Camera Feed with ML) */}
        <div className="flex-1 p-4 flex flex-col overflow-hidden">
          <div className="flex items-center justify-between mb-2">
            <div className="flex items-center gap-2">
              <h3 className="text-xs font-semibold text-[rgba(235,235,245,0.5)] uppercase tracking-wide">CYRUS Vision</h3>
              {modelLoading && (
                <span className="flex items-center gap-1">
                  <Loader2 className="w-3 h-3 text-amber-400 animate-spin" />
                  <span className="text-[10px] text-amber-400">Loading ML...</span>
                </span>
              )}
              {cameraActive && !modelLoading && (
                <span className="flex items-center gap-1">
                  <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                  <span className="text-[10px] text-emerald-400">LIVE</span>
                </span>
              )}
            </div>
            <button
              onClick={toggleCamera}
              disabled={modelLoading}
              className={`p-1.5 rounded-lg transition-colors ${
                cameraActive 
                  ? "bg-emerald-500/20 text-emerald-400 hover:bg-emerald-500/30" 
                  : modelLoading
                    ? "text-amber-400 cursor-wait"
                    : "text-[rgba(235,235,245,0.4)] hover:bg-[rgba(120,120,128,0.2)]"
              }`}
            >
              {cameraActive ? <Camera className="w-4 h-4" /> : <CameraOff className="w-4 h-4" />}
            </button>
          </div>

          {/* Camera Feed with ML Overlay */}
          <div className="flex-1 bg-black rounded-xl border border-[rgba(84,84,88,0.65)] overflow-hidden relative min-h-[180px]">
            {cameraActive || modelLoading ? (
              <>
                <video
                  ref={videoRef}
                  autoPlay
                  playsInline
                  muted
                  className="w-full h-full object-cover"
                />
                {/* Canvas overlay for bounding boxes */}
                <canvas
                  ref={canvasRef}
                  className="absolute inset-0 w-full h-full object-cover pointer-events-none"
                />
                {/* Vision overlay */}
                <div className="absolute inset-0 pointer-events-none">
                  <div className="absolute top-2 left-2 flex items-center gap-1.5">
                    <Eye className="w-3 h-3 text-cyan-400" />
                    <span className="text-[10px] text-cyan-400 font-mono">
                      {modelLoading ? "INITIALIZING..." : "VISUAL CORTEX ACTIVE"}
                    </span>
                  </div>
                  <div className="absolute top-2 right-2 text-[10px] text-emerald-400 font-mono">
                    {detectedObjects.length > 0 && `${detectedObjects.length} OBJECTS`}
                  </div>
                </div>
              </>
            ) : (
              <div className="w-full h-full flex flex-col items-center justify-center">
                <div className="w-12 h-12 rounded-full border-2 border-dashed border-[rgba(84,84,88,0.65)] flex items-center justify-center mb-3">
                  <CameraOff className="w-6 h-6 text-[rgba(235,235,245,0.3)]" />
                </div>
                <p className="text-xs text-[rgba(235,235,245,0.4)] text-center mb-1">Vision Offline</p>
                <p className="text-[10px] text-[rgba(235,235,245,0.3)]">Click camera to activate ML vision</p>
              </div>
            )}
          </div>

          {/* Detected Objects List */}
          {cameraActive && detectedObjects.length > 0 && (
            <div className="mt-2 max-h-20 overflow-auto">
              <div className="flex flex-wrap gap-1">
                {detectedObjects.map((obj, i) => (
                  <span 
                    key={i}
                    className="inline-flex items-center gap-1 px-2 py-0.5 bg-emerald-500/20 text-emerald-400 text-[10px] rounded-full font-mono"
                  >
                    <span className="w-1.5 h-1.5 bg-emerald-400 rounded-full"></span>
                    {obj.class} {Math.round(obj.score * 100)}%
                  </span>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

client/src/pages/QuantumPage.tsx.content:
import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import {
  Zap,
  Atom,
  Activity,
  Play,
  Pause,
  RotateCcw,
  Loader2,
  CheckCircle2,
  Cpu,
  Layers,
} from "lucide-react";

interface QuantumCircuit {
  id: string;
  name: string;
  qubits: number;
  gates: string[];
  coherence: number;
  accuracy: number;
}

interface QuantumState {
  circuits: QuantumCircuit[];
  totalQubits: number;
  coherenceLevel: number;
  processingPower: number;
}

export function QuantumPage() {
  const [selectedCircuit, setSelectedCircuit] = useState<string | null>(null);
  const [newCircuitQubits, setNewCircuitQubits] = useState(4);
  const [simulationResult, setSimulationResult] = useState<any>(null);

  const defaultGatePatterns: Record<string, string[]> = {
    "bell-state": ["H", "CNOT"],
    "ghz-state": ["H", "CNOT", "CNOT"],
    "quantum-fourier-2": ["H", "T", "S", "CNOT"],
  };

  const { data: quantumState, isLoading, refetch } = useQuery<QuantumState>({
    queryKey: ["/api/upgrades/quantum/status"],
    queryFn: async () => {
      const res = await fetch("/api/upgrades/quantum/status");
      if (!res.ok) {
        return {
          circuits: [
            { id: "circuit-1", name: "Hadamard Gate Array", qubits: 4, gates: ["H", "CNOT", "X"], coherence: 0.95, accuracy: 0.998 },
            { id: "circuit-2", name: "Grover Search", qubits: 8, gates: ["H", "X", "Z", "CNOT"], coherence: 0.92, accuracy: 0.995 },
            { id: "circuit-3", name: "Quantum Fourier", qubits: 6, gates: ["H", "T", "S", "CNOT"], coherence: 0.89, accuracy: 0.991 },
          ],
          totalQubits: 18,
          coherenceLevel: 0.92,
          processingPower: 99.9,
        };
      }
      const data = await res.json();
      const circuits = (data.circuits || []).map((c: any) => ({
        id: c.id,
        name: c.name,
        qubits: c.qubits,
        gates: defaultGatePatterns[c.name] || Array.from({ length: c.gates || 2 }, (_, i) => ["H", "X", "CNOT", "T", "S", "Z", "Y"][i % 7]),
        coherence: c.coherence ?? 0.95,
        accuracy: c.accuracy ?? 0.99,
      }));
      return {
        circuits,
        totalQubits: circuits.reduce((sum: number, c: QuantumCircuit) => sum + c.qubits, 0),
        coherenceLevel: data.status?.coherenceThreshold ?? 0.95,
        processingPower: (data.status?.simulationAccuracy ?? 0.999) * 100,
      };
    },
  });

  const simulateMutation = useMutation({
    mutationFn: async (circuitId: string) => {
      const res = await fetch("/api/upgrades/quantum/simulate", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ circuitId }),
      });
      if (!res.ok) {
        return {
          success: true,
          result: {
            measurements: Array(8).fill(0).map(() => Math.random()),
            fidelity: 0.994,
            executionTime: 1.23,
            stateVector: ["0.707|00⟩", "0.707|11⟩"],
          },
        };
      }
      return res.json();
    },
    onSuccess: (data) => {
      setSimulationResult(data.result);
    },
  });

  const createCircuitMutation = useMutation({
    mutationFn: async () => {
      const res = await fetch("/api/upgrades/quantum/create", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ qubits: newCircuitQubits, gates: ["H", "CNOT"] }),
      });
      if (!res.ok) throw new Error("Failed to create circuit");
      return res.json();
    },
    onSuccess: () => {
      refetch();
    },
  });

  const gateColors: Record<string, string> = {
    H: "bg-blue-500",
    X: "bg-red-500",
    Y: "bg-green-500",
    Z: "bg-purple-500",
    CNOT: "bg-amber-500",
    T: "bg-cyan-500",
    S: "bg-pink-500",
  };

  return (
    <div className="h-full overflow-y-auto bg-black p-4 md:p-6">
      <div className="max-w-6xl mx-auto space-y-6">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-gradient-to-br from-violet-500 to-purple-600 rounded-xl flex items-center justify-center">
            <Atom className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-2xl font-bold">Quantum Neural Networks</h1>
            <p className="text-[rgba(235,235,245,0.5)]">Quantum Circuit Simulation & Processing</p>
          </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          <div className="bg-[#1c1c1e] border border-[rgba(84,84,88,0.65)] rounded-xl p-4">
            <div className="flex items-center gap-2 mb-2">
              <Cpu className="w-5 h-5 text-violet-400" />
              <span className="text-sm text-[rgba(235,235,245,0.5)]">Total Qubits</span>
            </div>
            <p className="text-3xl font-bold text-violet-400">{quantumState?.totalQubits || 0}</p>
          </div>

          <div className="bg-[#1c1c1e] border border-[rgba(84,84,88,0.65)] rounded-xl p-4">
            <div className="flex items-center gap-2 mb-2">
              <Layers className="w-5 h-5 text-blue-400" />
              <span className="text-sm text-[rgba(235,235,245,0.5)]">Circuits</span>
            </div>
            <p className="text-3xl font-bold text-blue-400">{quantumState?.circuits?.length || 0}</p>
          </div>

          <div className="bg-[#1c1c1e] border border-[rgba(84,84,88,0.65)] rounded-xl p-4">
            <div className="flex items-center gap-2 mb-2">
              <Activity className="w-5 h-5 text-cyan-400" />
              <span className="text-sm text-[rgba(235,235,245,0.5)]">Coherence</span>
            </div>
            <p className="text-3xl font-bold text-cyan-400">
              {((quantumState?.coherenceLevel || 0) * 100).toFixed(1)}%
            </p>
          </div>

          <div className="bg-[#1c1c1e] border border-[rgba(84,84,88,0.65)] rounded-xl p-4">
            <div className="flex items-center gap-2 mb-2">
              <Zap className="w-5 h-5 text-emerald-400" />
              <span className="text-sm text-[rgba(235,235,245,0.5)]">Accuracy</span>
            </div>
            <p className="text-3xl font-bold text-emerald-400">
              {(quantumState?.processingPower || 0).toFixed(1)}%
            </p>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          <div className="bg-[#1c1c1e] border border-[rgba(84,84,88,0.65)] rounded-xl p-5">
            <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
              <Layers className="w-5 h-5 text-violet-400" />
              Quantum Circuits
            </h2>

            {isLoading ? (
              <div className="flex items-center justify-center py-8">
                <Loader2 className="w-6 h-6 animate-spin text-violet-400" />
              </div>
            ) : (
              <div className="space-y-3">
                {quantumState?.circuits?.map((circuit) => (
                  <div
                    key={circuit.id}
                    onClick={() => setSelectedCircuit(circuit.id)}
                    className={`bg-[#2c2c2e] rounded-lg p-4 cursor-pointer transition-all ${
                      selectedCircuit === circuit.id ? "ring-2 ring-violet-500" : "hover:bg-[#3c3c3e]"
                    }`}
                  >
                    <div className="flex items-center justify-between mb-3">
                      <div>
                        <h3 className="font-medium">{circuit.name}</h3>
                        <p className="text-xs text-[rgba(235,235,245,0.5)]">{circuit.qubits} qubits</p>
                      </div>
                      <div className="flex items-center gap-2">
                        <span className="text-xs px-2 py-1 bg-emerald-500/20 text-emerald-400 rounded-full">
                          {(circuit.accuracy * 100).toFixed(1)}%
                        </span>
                      </div>
                    </div>

                    <div className="flex gap-1 flex-wrap">
                      {circuit.gates.map((gate, i) => (
                        <span
                          key={i}
                          className={`px-2 py-1 rounded text-xs font-mono ${gateColors[gate] || "bg-gray-500"} text-white`}
                        >
                          {gate}
                        </span>
                      ))}
                    </div>

                    <div className="mt-3 flex items-center gap-2">
                      <span className="text-xs text-[rgba(235,235,245,0.4)]">Coherence:</span>
                      <div className="flex-1 h-1.5 bg-[#1c1c1e] rounded-full overflow-hidden">
                        <div
                          className="h-full bg-gradient-to-r from-violet-500 to-purple-500"
                          style={{ width: `${circuit.coherence * 100}%` }}
                        />
                      </div>
                      <span className="text-xs text-violet-400">{(circuit.coherence * 100).toFixed(0)}%</span>
                    </div>
                  </div>
                ))}
              </div>
            )}

            <div className="mt-4 pt-4 border-t border-[rgba(84,84,88,0.65)]">
              <div className="flex items-center gap-3">
                <input
                  type="number"
                  min={2}
                  max={16}
                  value={newCircuitQubits}
                  onChange={(e) => setNewCircuitQubits(parseInt(e.target.value) || 2)}
                  className="w-20 bg-[#2c2c2e] border border-[rgba(84,84,88,0.65)] rounded-lg px-3 py-2 text-white"
                />
                <span className="text-sm text-[rgba(235,235,245,0.5)]">qubits</span>
                <button
                  onClick={() => createCircuitMutation.mutate()}
                  disabled={createCircuitMutation.isPending}
                  className="flex-1 bg-violet-600 hover:bg-violet-700 text-white font-medium py-2 rounded-lg transition-colors disabled:opacity-50"
                >
                  Create Circuit
                </button>
              </div>
            </div>
          </div>

          <div className="bg-[#1c1c1e] border border-[rgba(84,84,88,0.65)] rounded-xl p-5">
            <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
              <Play className="w-5 h-5 text-emerald-400" />
              Quantum Simulation
            </h2>

            {selectedCircuit ? (
              <div className="space-y-4">
                <div className="bg-[#2c2c2e] rounded-lg p-4">
                  <div className="flex items-center justify-between mb-3">
                    <span className="text-sm text-[rgba(235,235,245,0.5)]">Selected Circuit</span>
                    <span className="text-sm font-medium">
                      {quantumState?.circuits?.find(c => c.id === selectedCircuit)?.name}
                    </span>
                  </div>
                  <button
                    onClick={() => simulateMutation.mutate(selectedCircuit)}
                    disabled={simulateMutation.isPending}
                    className="w-full bg-gradient-to-r from-emerald-500 to-cyan-500 hover:from-emerald-600 hover:to-cyan-600 text-white font-semibold py-3 rounded-lg flex items-center justify-center gap-2 transition-all disabled:opacity-50"
                  >
                    {simulateMutation.isPending ? (
                      <>
                        <Loader2 className="w-5 h-5 animate-spin" />
                        Simulating...
                      </>
                    ) : (
                      <>
                        <Play className="w-5 h-5" />
                        Run Simulation
                      </>
                    )}
                  </button>
                </div>

                {simulationResult && (
                  <div className="space-y-3">
                    <div className="bg-[#2c2c2e] rounded-lg p-4">
                      <h3 className="text-sm font-medium mb-3">State Vector</h3>
                      <div className="flex flex-wrap gap-2">
                        {simulationResult.stateVector?.map((state: string, i: number) => (
                          <span key={i} className="px-3 py-1 bg-violet-500/20 text-violet-300 rounded font-mono text-sm">
                            {state}
                          </span>
                        ))}
                      </div>
                    </div>

                    <div className="grid grid-cols-2 gap-3">
                      <div className="bg-[#2c2c2e] rounded-lg p-4">
                        <p className="text-xs text-[rgba(235,235,245,0.5)] mb-1">Fidelity</p>
                        <p className="text-2xl font-bold text-emerald-400">
                          {(simulationResult.fidelity * 100).toFixed(2)}%
                        </p>
                      </div>
                      <div className="bg-[#2c2c2e] rounded-lg p-4">
                        <p className="text-xs text-[rgba(235,235,245,0.5)] mb-1">Execution Time</p>
                        <p className="text-2xl font-bold text-cyan-400">
                          {simulationResult.executionTime?.toFixed(2)}ms
                        </p>
                      </div>
                    </div>

                    <div className="bg-[#2c2c2e] rounded-lg p-4">
                      <h3 className="text-sm font-medium mb-3">Measurement Probabilities</h3>
                      <div className="space-y-2">
                        {simulationResult.measurements?.slice(0, 4).map((prob: number, i: number) => (
                          <div key={i} className="flex items-center gap-2">
                            <span className="text-xs font-mono text-[rgba(235,235,245,0.5)] w-16">
                              |{i.toString(2).padStart(2, "0")}⟩
                            </span>
                            <div className="flex-1 h-2 bg-[#1c1c1e] rounded-full overflow-hidden">
                              <div
                                className="h-full bg-gradient-to-r from-violet-500 to-purple-500"
                                style={{ width: `${prob * 100}%` }}
                              />
                            </div>
                            <span className="text-xs text-violet-400 w-12 text-right">
                              {(prob * 100).toFixed(1)}%
                            </span>
                          </div>
                        ))}
                      </div>
                    </div>
                  </div>
                )}
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center py-12 text-center">
                <div className="w-16 h-16 bg-violet-500/20 rounded-xl flex items-center justify-center mb-4">
                  <Atom className="w-8 h-8 text-violet-400" />
                </div>
                <h3 className="text-lg font-semibold mb-2">Select a Circuit</h3>
                <p className="text-[rgba(235,235,245,0.5)] max-w-sm">
                  Choose a quantum circuit from the list to run simulations and view results.
                </p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

server/ai/upgrades/emotional-cognition.t.content:
import OpenAI from 'openai';
import { experienceMemory } from '../experience-memory';

const openai = new OpenAI({
  apiKey: process.env.AI_INTEGRATIONS_OPENAI_API_KEY || process.env.OPENAI_API_KEY,
  baseURL: process.env.AI_INTEGRATIONS_OPENAI_BASE_URL,
});

export interface EmotionState {
  primary: EmotionType;
  secondary: EmotionType | null;
  intensity: number;
  valence: number;
  arousal: number;
  dominance: number;
}

export type EmotionType = 
  | 'joy' | 'trust' | 'fear' | 'surprise'
  | 'sadness' | 'disgust' | 'anger' | 'anticipation'
  | 'love' | 'submission' | 'awe' | 'disapproval'
  | 'remorse' | 'contempt' | 'aggressiveness' | 'optimism'
  | 'neutral';

export interface SentimentAnalysis {
  sentiment: 'positive' | 'negative' | 'neutral' | 'mixed';
  score: number;
  confidence: number;
  aspects: Array<{
    aspect: string;
    sentiment: 'positive' | 'negative' | 'neutral';
    score: number;
  }>;
}

export interface EmotionalContext {
  userEmotion: EmotionState;
  conversationMood: EmotionState;
  emotionalTrend: 'improving' | 'declining' | 'stable';
  empathyLevel: number;
  suggestedTone: string;
  triggerWords: string[];
  emotionalNeeds: string[];
}

export interface CrisisIndicators {
  isCrisis: boolean;
  severity: 'low' | 'medium' | 'high' | 'critical';
  indicators: string[];
  recommendedAction: string;
  escalationNeeded: boolean;
}

export class EmotionalCognitionEngine {
  private emotionHistory: EmotionState[] = [];
  private conversationEmotionMap: Map<string, EmotionState[]> = new Map();
  private empathyPatterns: Map<string, string[]> = new Map();

  private emotionKeywords: Record<EmotionType, string[]> = {
    joy: ['happy', 'glad', 'delighted', 'pleased', 'excited', 'wonderful', 'great', 'amazing', 'fantastic', 'love'],
    trust: ['believe', 'confident', 'secure', 'safe', 'reliable', 'trust', 'faith', 'depend'],
    fear: ['afraid', 'scared', 'terrified', 'anxious', 'worried', 'nervous', 'panic', 'dread'],
    surprise: ['shocked', 'amazed', 'astonished', 'unexpected', 'wow', 'unbelievable', 'startled'],
    sadness: ['sad', 'unhappy', 'depressed', 'down', 'crying', 'lonely', 'miserable', 'heartbroken', 'grief'],
    disgust: ['disgusted', 'revolted', 'gross', 'sick', 'repulsed', 'awful', 'terrible'],
    anger: ['angry', 'mad', 'furious', 'annoyed', 'frustrated', 'irritated', 'hate', 'rage'],
    anticipation: ['expecting', 'waiting', 'eager', 'looking forward', 'hope', 'anticipate'],
    love: ['adore', 'cherish', 'affection', 'devotion', 'passionate', 'care deeply'],
    submission: ['obey', 'comply', 'surrender', 'yield', 'accept'],
    awe: ['amazed', 'wonder', 'magnificent', 'breathtaking', 'incredible'],
    disapproval: ['disapprove', 'reject', 'deny', 'refuse', 'disagree'],
    remorse: ['sorry', 'regret', 'apologize', 'guilt', 'ashamed'],
    contempt: ['scorn', 'disdain', 'mock', 'belittle', 'despise'],
    aggressiveness: ['attack', 'fight', 'destroy', 'conquer', 'dominate'],
    optimism: ['hopeful', 'positive', 'bright', 'promising', 'confident'],
    neutral: []
  };

  private crisisKeywords = [
    'suicide', 'kill myself', 'end my life', 'want to die', 'no reason to live',
    'self-harm', 'hurt myself', 'cutting', 'overdose', 'emergency',
    'abuse', 'violence', 'danger', 'threatened', 'help me'
  ];

  constructor() {
    console.log('[Emotional Cognition] Initializing advanced emotional intelligence engine');
    this.initializeEmpathyPatterns();
  }

  private initializeEmpathyPatterns(): void {
    this.empathyPatterns.set('sadness', [
      "I can hear how difficult this is for you, and I want you to know I'm here.",
      "It's completely understandable to feel this way. Your feelings are valid.",
      "I'm sorry you're going through this. Let's talk about it.",
      "That sounds really hard. I'm here to listen and support you."
    ]);

    this.empathyPatterns.set('anger', [
      "I understand your frustration. That situation sounds really challenging.",
      "It makes sense that you're upset. Let's work through this together.",
      "Your feelings are completely valid. What would help you feel better right now?"
    ]);

    this.empathyPatterns.set('fear', [
      "It's okay to feel scared. I'm here with you.",
      "That does sound worrying. Let's think about this together.",
      "I understand this is causing you anxiety. What would help you feel safer?"
    ]);

    this.empathyPatterns.set('joy', [
      "That's wonderful! I'm so happy for you!",
      "What amazing news! Tell me more!",
      "I can feel your excitement! This is great!"
    ]);
  }

  async analyzeEmotion(text: string): Promise<EmotionState> {
    const lowerText = text.toLowerCase();

    const emotionScores: Record<EmotionType, number> = {
      joy: 0, trust: 0, fear: 0, surprise: 0,
      sadness: 0, disgust: 0, anger: 0, anticipation: 0,
      love: 0, submission: 0, awe: 0, disapproval: 0,
      remorse: 0, contempt: 0, aggressiveness: 0, optimism: 0,
      neutral: 0.1
    };

    for (const [emotion, keywords] of Object.entries(this.emotionKeywords)) {
      for (const keyword of keywords) {
        if (lowerText.includes(keyword)) {
          emotionScores[emotion as EmotionType] += 0.2;
        }
      }
    }

    try {
      const response = await openai.chat.completions.create({
        model: 'gpt-4o',
        messages: [
          {
            role: 'system',
            content: `Analyze the emotional content of the text. Return a JSON object with:
- primary_emotion: one of [joy, trust, fear, surprise, sadness, disgust, anger, anticipation, love, awe, remorse, optimism, neutral]
- secondary_emotion: optional secondary emotion or null
- intensity: 0-1 scale of emotional intensity
- valence: -1 to 1 (-1 = very negative, 1 = very positive)
- arousal: 0-1 scale of emotional activation/energy
Return only valid JSON.`
          },
          { role: 'user', content: text }
        ],
        max_tokens: 200,
        temperature: 0.3
      });

      const content = response.choices[0].message.content || '{}';
      const parsed = JSON.parse(content.replace(/```json\n?|\n?```/g, ''));

      const state: EmotionState = {
        primary: parsed.primary_emotion || this.getHighestEmotion(emotionScores),
        secondary: parsed.secondary_emotion || null,
        intensity: parsed.intensity || 0.5,
        valence: parsed.valence || 0,
        arousal: parsed.arousal || 0.5,
        dominance: 0.5
      };

      this.emotionHistory.push(state);
      if (this.emotionHistory.length > 100) {
        this.emotionHistory = this.emotionHistory.slice(-50);
      }

      return state;
    } catch (error) {
      console.error('[Emotional Cognition] Analysis error:', error);
      return {
        primary: this.getHighestEmotion(emotionScores),
        secondary: null,
        intensity: 0.5,
        valence: 0,
        arousal: 0.5,
        dominance: 0.5
      };
    }
  }

  private getHighestEmotion(scores: Record<EmotionType, number>): EmotionType {
    let highest: EmotionType = 'neutral';
    let highestScore = 0;

    for (const [emotion, score] of Object.entries(scores)) {
      if (score > highestScore) {
        highestScore = score;
        highest = emotion as EmotionType;
      }
    }

    return highest;
  }

  async analyzeSentiment(text: string): Promise<SentimentAnalysis> {
    try {
      const response = await openai.chat.completions.create({
        model: 'gpt-4o',
        messages: [
          {
            role: 'system',
            content: `Analyze the sentiment of the text. Return a JSON object with:
- sentiment: "positive", "negative", "neutral", or "mixed"
- score: -1 to 1 scale
- confidence: 0-1 scale
- aspects: array of {aspect: string, sentiment: string, score: number} for different topics mentioned
Return only valid JSON.`
          },
          { role: 'user', content: text }
        ],
        max_tokens: 300,
        temperature: 0.3
      });

      const content = response.choices[0].message.content || '{}';
      const parsed = JSON.parse(content.replace(/```json\n?|\n?```/g, ''));

      return {
        sentiment: parsed.sentiment || 'neutral',
        score: parsed.score || 0,
        confidence: parsed.confidence || 0.5,
        aspects: parsed.aspects || []
      };
    } catch (error) {
      console.error('[Emotional Cognition] Sentiment analysis error:', error);
      return {
        sentiment: 'neutral',
        score: 0,
        confidence: 0.3,
        aspects: []
      };
    }
  }

  async getEmotionalContext(conversationHistory: Array<{ role: string; content: string }>): Promise<EmotionalContext> {
    const recentEmotions: EmotionState[] = [];

    for (const msg of conversationHistory.slice(-5)) {
      const emotion = await this.analyzeEmotion(msg.content);
      recentEmotions.push(emotion);
    }

    const userEmotions = recentEmotions.filter((_, i) => 
      conversationHistory.slice(-5)[i]?.role === 'user'
    );

    const latestUserEmotion = userEmotions[userEmotions.length - 1] || {
      primary: 'neutral' as EmotionType,
      secondary: null,
      intensity: 0.5,
      valence: 0,
      arousal: 0.5,
      dominance: 0.5
    };

    const avgValence = recentEmotions.reduce((sum, e) => sum + e.valence, 0) / recentEmotions.length || 0;
    const conversationMood: EmotionState = {
      primary: avgValence > 0.3 ? 'joy' : avgValence < -0.3 ? 'sadness' : 'neutral',
      secondary: null,
      intensity: Math.abs(avgValence),
      valence: avgValence,
      arousal: recentEmotions.reduce((sum, e) => sum + e.arousal, 0) / recentEmotions.length || 0.5,
      dominance: 0.5
    };

    let emotionalTrend: 'improving' | 'declining' | 'stable' = 'stable';
    if (userEmotions.length >= 2) {
      const recentValence = userEmotions.slice(-2).reduce((sum, e) => sum + e.valence, 0) / 2;
      const earlierValence = userEmotions.slice(0, -2).reduce((sum, e) => sum + e.valence, 0) / Math.max(1, userEmotions.length - 2);

      if (recentValence - earlierValence > 0.2) emotionalTrend = 'improving';
      else if (earlierValence - recentValence > 0.2) emotionalTrend = 'declining';
    }

    const triggerWords = this.extractTriggerWords(conversationHistory.map(m => m.content).join(' '));
    const emotionalNeeds = this.identifyEmotionalNeeds(latestUserEmotion);
    const suggestedTone = this.getSuggestedTone(latestUserEmotion, emotionalTrend);

    return {
      userEmotion: latestUserEmotion,
      conversationMood,
      emotionalTrend,
      empathyLevel: this.calculateEmpathyLevel(latestUserEmotion),
      suggestedTone,
      triggerWords,
      emotionalNeeds
    };
  }

  private extractTriggerWords(text: string): string[] {
    const triggers: string[] = [];
    const lowerText = text.toLowerCase();

    for (const [emotion, keywords] of Object.entries(this.emotionKeywords)) {
      for (const keyword of keywords) {
        if (lowerText.includes(keyword) && !triggers.includes(keyword)) {
          triggers.push(keyword);
        }
      }
    }

    return triggers.slice(0, 10);
  }

  private identifyEmotionalNeeds(emotion: EmotionState): string[] {
    const needs: string[] = [];

    switch (emotion.primary) {
      case 'sadness':
        needs.push('comfort', 'understanding', 'support', 'presence');
        break;
      case 'anger':
        needs.push('validation', 'space', 'solutions', 'acknowledgment');
        break;
      case 'fear':
        needs.push('safety', 'reassurance', 'information', 'companionship');
        break;
      case 'joy':
        needs.push('celebration', 'sharing', 'connection');
        break;
      case 'trust':
        needs.push('consistency', 'reliability', 'honesty');
        break;
      default:
        needs.push('engagement', 'attention', 'understanding');
    }

    return needs;
  }

  private calculateEmpathyLevel(emotion: EmotionState): number {
    if (emotion.valence < -0.5 || emotion.intensity > 0.7) {
      return 0.9;
    } else if (emotion.valence < 0) {
      return 0.7;
    }
    return 0.5;
  }

  private getSuggestedTone(emotion: EmotionState, trend: 'improving' | 'declining' | 'stable'): string {
    if (emotion.valence < -0.5) {
      return 'warm, supportive, and gentle';
    } else if (emotion.primary === 'anger') {
      return 'calm, validating, and solution-oriented';
    } else if (emotion.primary === 'fear') {
      return 'reassuring, calm, and protective';
    } else if (emotion.valence > 0.5) {
      return 'enthusiastic, celebratory, and engaging';
    } else if (trend === 'declining') {
      return 'supportive and uplifting';
    }
    return 'friendly, warm, and conversational';
  }

  detectCrisis(text: string): CrisisIndicators {
    const lowerText = text.toLowerCase();
    const foundIndicators: string[] = [];

    for (const keyword of this.crisisKeywords) {
      if (lowerText.includes(keyword)) {
        foundIndicators.push(keyword);
      }
    }

    if (foundIndicators.length === 0) {
      return {
        isCrisis: false,
        severity: 'low',
        indicators: [],
        recommendedAction: 'Continue normal conversation',
        escalationNeeded: false
      };
    }

    const severity = foundIndicators.length >= 3 ? 'critical' 
      : foundIndicators.length >= 2 ? 'high' 
      : 'medium';

    const isCritical = severity === 'critical' || 
      foundIndicators.some(i => ['suicide', 'kill myself', 'end my life'].includes(i));

    return {
      isCrisis: true,
      severity,
      indicators: foundIndicators,
      recommendedAction: isCritical 
        ? 'Provide immediate crisis resources and encourage professional help' 
        : 'Express concern and offer support resources',
      escalationNeeded: isCritical
    };
  }

  getEmpathyResponse(emotion: EmotionType): string {
    const patterns = this.empathyPatterns.get(emotion);
    if (patterns && patterns.length > 0) {
      return patterns[Math.floor(Math.random() * patterns.length)];
    }
    return "I hear you and I'm here for you.";
  }

  async generateEmotionallyIntelligentPrompt(
    userMessage: string,
    systemPrompt: string
  ): Promise<string> {
    const emotion = await this.analyzeEmotion(userMessage);
    const crisis = this.detectCrisis(userMessage);

    let emotionalGuidance = '';

    if (crisis.isCrisis) {
      emotionalGuidance = `
CRISIS DETECTED - SEVERITY: ${crisis.severity.toUpperCase()}
Indicators: ${crisis.indicators.join(', ')}
Action: ${crisis.recommendedAction}
Respond with extreme care, empathy, and provide appropriate resources.`;
    } else {
      emotionalGuidance = `
EMOTIONAL STATE ANALYSIS:
- Primary Emotion: ${emotion.primary} (intensity: ${(emotion.intensity * 100).toFixed(0)}%)
- Emotional Valence: ${emotion.valence > 0 ? 'Positive' : emotion.valence < 0 ? 'Negative' : 'Neutral'}
- Suggested Tone: ${this.getSuggestedTone(emotion, 'stable')}
- Emotional Needs: ${this.identifyEmotionalNeeds(emotion).join(', ')}

Adapt your response to acknowledge and address the user's emotional state appropriately.`;
    }

    return `${systemPrompt}

${emotionalGuidance}`;
  }

  getEmotionStats(): {
    totalAnalyzed: number;
    emotionDistribution: Record<EmotionType, number>;
    averageValence: number;
    averageIntensity: number;
  } {
    const distribution: Record<EmotionType, number> = {} as Record<EmotionType, number>;

    for (const emotion of this.emotionHistory) {
      distribution[emotion.primary] = (distribution[emotion.primary] || 0) + 1;
    }

    const avgValence = this.emotionHistory.length > 0
      ? this.emotionHistory.reduce((sum, e) => sum + e.valence, 0) / this.emotionHistory.length
      : 0;

    const avgIntensity = this.emotionHistory.length > 0
      ? this.emotionHistory.reduce((sum, e) => sum + e.intensity, 0) / this.emotionHistory.length
      : 0;

    return {
      totalAnalyzed: this.emotionHistory.length,
      emotionDistribution: distribution,
      averageValence: avgValence,
      averageIntensity: avgIntensity
    };
  }
}

export const emotionalCognition = new EmotionalCognitionEngine();

