import OpenAI from "openai";

let openaiClient: OpenAI | null = null;

function getOpenAI(): OpenAI | null {
  const apiKey = process.env.OPENAI_API_KEY || process.env.AI_INTEGRATIONS_OPENAI_API_KEY;
  if (!apiKey) {
    return null;
  }
  if (!openaiClient) {
    openaiClient = new OpenAI({ apiKey });
  }
  return openaiClient;
}

interface EEGChannel {
  id: string;
  name: string;
  position: { x: number; y: number; z: number };
  impedance: number;
  signalQuality: number;
}

interface BrainWaveData {
  timestamp: number;
  channels: Record<string, number[]>;
  sampleRate: number;
}

interface FrequencyBand {
  name: 'delta' | 'theta' | 'alpha' | 'beta' | 'gamma';
  minFreq: number;
  maxFreq: number;
  power: number;
  dominance: number;
}

interface CognitiveState {
  focus: number;
  relaxation: number;
  stress: number;
  engagement: number;
  drowsiness: number;
  mentalWorkload: number;
  emotionalValence: number;
  timestamp: Date;
}

interface NeuralPattern {
  id: string;
  name: string;
  type: 'motor_imagery' | 'ssvep' | 'p300' | 'emotion' | 'attention' | 'meditation' | 'custom';
  signature: number[];
  accuracy: number;
  trainingExamples: number;
}

interface BCICommand {
  id: string;
  name: string;
  pattern: NeuralPattern;
  action: string;
  parameters: Record<string, any>;
  confidence: number;
  activationThreshold: number;
}

interface NeurofeedbackSession {
  id: string;
  target: 'focus' | 'relaxation' | 'alpha_enhancement' | 'stress_reduction' | 'peak_performance';
  duration: number;
  startTime: Date;
  metrics: { timestamp: number; score: number }[];
  currentScore: number;
  improvement: number;
}

export class BioNeuralInterface {
  private channels: Map<string, EEGChannel> = new Map();
  private patterns: Map<string, NeuralPattern> = new Map();
  private commands: Map<string, BCICommand> = new Map();
  private brainwaveHistory: BrainWaveData[] = [];
  private cognitiveStates: CognitiveState[] = [];
  private activeSessions: Map<string, NeurofeedbackSession> = new Map();
  private isConnected = false;
  private sampleRate = 256;

  constructor() {
    console.log("[Bio-Neural Interface] Initializing brain-computer interface simulation");
    this.initializeChannels();
    this.initializeDefaultPatterns();
    this.startSimulation();
  }

  private initializeChannels(): void {
    const electrodePositions = [
      { name: 'Fp1', position: { x: -0.03, y: 0.08, z: 0.02 } },
      { name: 'Fp2', position: { x: 0.03, y: 0.08, z: 0.02 } },
      { name: 'F3', position: { x: -0.05, y: 0.05, z: 0.04 } },
      { name: 'F4', position: { x: 0.05, y: 0.05, z: 0.04 } },
      { name: 'C3', position: { x: -0.06, y: 0, z: 0.06 } },
      { name: 'C4', position: { x: 0.06, y: 0, z: 0.06 } },
      { name: 'P3', position: { x: -0.05, y: -0.05, z: 0.04 } },
      { name: 'P4', position: { x: 0.05, y: -0.05, z: 0.04 } },
      { name: 'O1', position: { x: -0.03, y: -0.08, z: 0.02 } },
      { name: 'O2', position: { x: 0.03, y: -0.08, z: 0.02 } },
      { name: 'Fz', position: { x: 0, y: 0.06, z: 0.05 } },
      { name: 'Cz', position: { x: 0, y: 0, z: 0.08 } },
      { name: 'Pz', position: { x: 0, y: -0.06, z: 0.05 } },
      { name: 'T3', position: { x: -0.08, y: 0, z: 0.02 } },
      { name: 'T4', position: { x: 0.08, y: 0, z: 0.02 } },
      { name: 'T5', position: { x: -0.07, y: -0.04, z: 0.02 } },
      { name: 'T6', position: { x: 0.07, y: -0.04, z: 0.02 } }
    ];

    for (const electrode of electrodePositions) {
      const channel: EEGChannel = {
        id: `ch_${electrode.name}`,
        name: electrode.name,
        position: electrode.position,
        impedance: 5 + Math.random() * 5,
        signalQuality: 0.8 + Math.random() * 0.2
      };
      this.channels.set(channel.id, channel);
    }
  }

  private initializeDefaultPatterns(): void {
    const defaultPatterns: Omit<NeuralPattern, 'id'>[] = [
      {
        name: 'Left Hand Motor Imagery',
        type: 'motor_imagery',
        signature: [0.8, 0.2, 0.1, 0.3, 0.9, 0.2, 0.1, 0.2],
        accuracy: 0.85,
        trainingExamples: 500
      },
      {
        name: 'Right Hand Motor Imagery',
        type: 'motor_imagery',
        signature: [0.2, 0.8, 0.3, 0.1, 0.2, 0.9, 0.2, 0.1],
        accuracy: 0.87,
        trainingExamples: 500
      },
      {
        name: 'Focus State',
        type: 'attention',
        signature: [0.3, 0.3, 0.7, 0.7, 0.4, 0.4, 0.2, 0.2],
        accuracy: 0.92,
        trainingExamples: 1000
      },
      {
        name: 'Relaxation State',
        type: 'meditation',
        signature: [0.2, 0.2, 0.3, 0.3, 0.8, 0.8, 0.6, 0.6],
        accuracy: 0.89,
        trainingExamples: 800
      },
      {
        name: 'P300 Target Detection',
        type: 'p300',
        signature: [0.1, 0.1, 0.2, 0.2, 0.3, 0.3, 0.9, 0.9],
        accuracy: 0.91,
        trainingExamples: 1200
      }
    ];

    for (const pattern of defaultPatterns) {
      this.registerPattern(pattern);
    }
  }

  private startSimulation(): void {
    setInterval(() => {
      if (this.isConnected) {
        this.generateSimulatedBrainwave();
        this.updateCognitiveState();
      }
    }, 100);
  }

  connect(deviceType: 'openbci' | 'emotiv' | 'muse' | 'neurosky' | 'simulation' = 'simulation'): {
    success: boolean;
    device: string;
    channels: number;
    sampleRate: number;
  } {
    this.isConnected = true;

    return {
      success: true,
      device: deviceType,
      channels: this.channels.size,
      sampleRate: this.sampleRate
    };
  }

  disconnect(): void {
    this.isConnected = false;
  }

  private generateSimulatedBrainwave(): void {
    const timestamp = Date.now();
    const channels: Record<string, number[]> = {};

    for (const [id, channel] of this.channels) {
      const samples: number[] = [];
      for (let i = 0; i < 25; i++) {
        const delta = Math.sin(2 * Math.PI * 2 * (timestamp + i) / 1000) * 20;
        const theta = Math.sin(2 * Math.PI * 6 * (timestamp + i) / 1000) * 10;
        const alpha = Math.sin(2 * Math.PI * 10 * (timestamp + i) / 1000) * 15;
        const beta = Math.sin(2 * Math.PI * 20 * (timestamp + i) / 1000) * 5;
        const gamma = Math.sin(2 * Math.PI * 40 * (timestamp + i) / 1000) * 2;
        const noise = (Math.random() - 0.5) * 5;

        samples.push(delta + theta + alpha + beta + gamma + noise);
      }
      channels[id] = samples;
    }

    const data: BrainWaveData = {
      timestamp,
      channels,
      sampleRate: this.sampleRate
    };

    this.brainwaveHistory.push(data);
    if (this.brainwaveHistory.length > 100) {
      this.brainwaveHistory.shift();
    }
  }

  private updateCognitiveState(): void {
    const state: CognitiveState = {
      focus: 0.4 + Math.random() * 0.4,
      relaxation: 0.3 + Math.random() * 0.5,
      stress: 0.1 + Math.random() * 0.3,
      engagement: 0.5 + Math.random() * 0.3,
      drowsiness: 0.1 + Math.random() * 0.2,
      mentalWorkload: 0.3 + Math.random() * 0.4,
      emotionalValence: 0.5 + (Math.random() - 0.5) * 0.4,
      timestamp: new Date()
    };

    this.cognitiveStates.push(state);
    if (this.cognitiveStates.length > 1000) {
      this.cognitiveStates.shift();
    }
  }

  analyzeFrequencyBands(): FrequencyBand[] {
    const bands: FrequencyBand[] = [
      { name: 'delta', minFreq: 0.5, maxFreq: 4, power: 20 + Math.random() * 10, dominance: 0 },
      { name: 'theta', minFreq: 4, maxFreq: 8, power: 15 + Math.random() * 10, dominance: 0 },
      { name: 'alpha', minFreq: 8, maxFreq: 13, power: 25 + Math.random() * 15, dominance: 0 },
      { name: 'beta', minFreq: 13, maxFreq: 30, power: 10 + Math.random() * 10, dominance: 0 },
      { name: 'gamma', minFreq: 30, maxFreq: 100, power: 5 + Math.random() * 5, dominance: 0 }
    ];

    const totalPower = bands.reduce((sum, b) => sum + b.power, 0);
    for (const band of bands) {
      band.dominance = band.power / totalPower;
    }

    return bands;
  }

  getCurrentCognitiveState(): CognitiveState | null {
    return this.cognitiveStates.length > 0
      ? this.cognitiveStates[this.cognitiveStates.length - 1]
      : null;
  }

  registerPattern(config: Omit<NeuralPattern, 'id'>): NeuralPattern {
    const pattern: NeuralPattern = {
      ...config,
      id: `pattern_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`
    };

    this.patterns.set(pattern.id, pattern);
    return pattern;
  }

  createCommand(config: {
    name: string;
    patternId: string;
    action: string;
    parameters?: Record<string, any>;
    threshold?: number;
  }): BCICommand {
    const pattern = this.patterns.get(config.patternId);
    if (!pattern) throw new Error(`Pattern ${config.patternId} not found`);

    const command: BCICommand = {
      id: `cmd_${Date.now()}`,
      name: config.name,
      pattern,
      action: config.action,
      parameters: config.parameters || {},
      confidence: 0,
      activationThreshold: config.threshold || 0.7
    };

    this.commands.set(command.id, command);
    return command;
  }

  detectCommands(): { command: BCICommand; confidence: number }[] {
    const detectedCommands: { command: BCICommand; confidence: number }[] = [];

    for (const command of this.commands.values()) {
      const confidence = 0.5 + Math.random() * 0.5;
      if (confidence >= command.activationThreshold) {
        command.confidence = confidence;
        detectedCommands.push({ command, confidence });
      }
    }

    return detectedCommands;
  }

  startNeurofeedbackSession(target: NeurofeedbackSession['target'], durationMinutes: number): NeurofeedbackSession {
    const session: NeurofeedbackSession = {
      id: `nf_${Date.now()}`,
      target,
      duration: durationMinutes * 60 * 1000,
      startTime: new Date(),
      metrics: [],
      currentScore: 0.5,
      improvement: 0
    };

    this.activeSessions.set(session.id, session);

    const updateInterval = setInterval(() => {
      const elapsed = Date.now() - session.startTime.getTime();
      if (elapsed >= session.duration) {
        clearInterval(updateInterval);
        return;
      }

      const improvement = Math.min(0.3, elapsed / session.duration * 0.3);
      session.currentScore = 0.5 + improvement + (Math.random() - 0.5) * 0.1;
      session.improvement = improvement;
      session.metrics.push({
        timestamp: elapsed,
        score: session.currentScore
      });
    }, 1000);

    return session;
  }

  async interpretNeuralActivity(query?: string): Promise<{
    interpretation: string;
    cognitiveState: CognitiveState | null;
    frequencyBands: FrequencyBand[];
    recommendations: string[];
  }> {
    const state = this.getCurrentCognitiveState();
    const bands = this.analyzeFrequencyBands();

    const recommendations: string[] = [];
    if (state) {
      if (state.focus < 0.5) recommendations.push("Consider taking a short break or practicing focused breathing");
      if (state.stress > 0.6) recommendations.push("High stress detected - try relaxation techniques");
      if (state.drowsiness > 0.5) recommendations.push("Drowsiness detected - consider physical movement or fresh air");
      if (state.engagement < 0.4) recommendations.push("Low engagement - try changing tasks or environment");
    }

    const alphaDominant = bands.find(b => b.name === 'alpha')?.dominance || 0;
    if (alphaDominant > 0.3) recommendations.push("Strong alpha waves - good relaxed focus state");

    const openai = getOpenAI();
    if (!openai) {
      return {
        interpretation: `Neural analysis: ${state ? `Focus: ${(state.focus * 100).toFixed(0)}%` : 'Awaiting connection'} [AI unavailable]`,
        cognitiveState: state,
        frequencyBands: bands,
        recommendations
      };
    }

    try {
      const response = await openai.chat.completions.create({
        model: "gpt-4o",
        messages: [
          {
            role: "system",
            content: `You are CYRUS's Bio-Neural Interface module. Interpret brain activity patterns and provide insights.
Current cognitive state: ${state ? JSON.stringify(state) : 'Not available'}
Frequency bands: ${JSON.stringify(bands)}`
          },
          {
            role: "user",
            content: query || "Analyze current neural activity patterns"
          }
        ],
        max_tokens: 500
      });

      return {
        interpretation: response.choices[0].message.content || "Neural analysis complete.",
        cognitiveState: state,
        frequencyBands: bands,
        recommendations
      };
    } catch (error) {
      return {
        interpretation: `Neural activity analysis: ${state ? `Focus: ${(state.focus * 100).toFixed(0)}%, Relaxation: ${(state.relaxation * 100).toFixed(0)}%, Engagement: ${(state.engagement * 100).toFixed(0)}%` : 'Awaiting connection'}. Dominant frequency band: ${bands.reduce((max, b) => b.dominance > max.dominance ? b : max, bands[0]).name}.`,
        cognitiveState: state,
        frequencyBands: bands,
        recommendations
      };
    }
  }

  getChannels(): EEGChannel[] {
    return Array.from(this.channels.values());
  }

  getPatterns(): NeuralPattern[] {
    return Array.from(this.patterns.values());
  }

  getCommands(): BCICommand[] {
    return Array.from(this.commands.values());
  }

  getStatus(): {
    connected: boolean;
    channelCount: number;
    patternCount: number;
    commandCount: number;
    activeSessionCount: number;
    sampleRate: number;
    dataPoints: number;
  } {
    return {
      connected: this.isConnected,
      channelCount: this.channels.size,
      patternCount: this.patterns.size,
      commandCount: this.commands.size,
      activeSessionCount: this.activeSessions.size,
      sampleRate: this.sampleRate,
      dataPoints: this.brainwaveHistory.length
    };
  }
}

export const bioNeuralInterface = new BioNeuralInterface();

server/ai/upgrades/decentralized-intelli.content:
import { Worker, isMainThread, parentPort, workerData } from 'worker_threads';
import { EventEmitter } from 'events';
import crypto from 'crypto';

export interface DistributedTask {
  id: string;
  type: 'inference' | 'analysis' | 'embedding' | 'translation' | 'emotion' | 'synthesis';
  payload: any;
  priority: 'low' | 'normal' | 'high' | 'critical';
  createdAt: Date;
  timeout: number;
}

export interface TaskResult {
  taskId: string;
  success: boolean;
  result?: any;
  error?: string;
  processingTime: number;
  workerId: string;
}

export interface WorkerNode {
  id: string;
  status: 'idle' | 'busy' | 'error' | 'offline';
  currentTask?: string;
  tasksCompleted: number;
  averageProcessingTime: number;
  lastActivity: Date;
  specialization?: string[];
}

export interface ClusterStats {
  totalWorkers: number;
  activeWorkers: number;
  idleWorkers: number;
  tasksInQueue: number;
  tasksProcessing: number;
  tasksCompleted: number;
  averageLatency: number;
  throughput: number;
}

export class DecentralizedIntelligenceNetwork extends EventEmitter {
  private workers: Map<string, WorkerNode> = new Map();
  private taskQueue: DistributedTask[] = [];
  private processingTasks: Map<string, DistributedTask> = new Map();
  private completedTasks: Map<string, TaskResult> = new Map();
  private taskPromises: Map<string, { resolve: Function; reject: Function; timeout: NodeJS.Timeout }> = new Map();

  private maxWorkers: number = 4;
  private maxQueueSize: number = 1000;
  private defaultTimeout: number = 30000;
  private tasksCompletedTotal: number = 0;
  private totalProcessingTime: number = 0;

  constructor(config?: { maxWorkers?: number; maxQueueSize?: number }) {
    super();
    this.maxWorkers = config?.maxWorkers || 4;
    this.maxQueueSize = config?.maxQueueSize || 1000;

    console.log(`[Decentralized Intelligence] Initializing distributed processing network with ${this.maxWorkers} worker capacity`);
    this.initializeWorkerPool();
    this.startTaskScheduler();
  }

  private initializeWorkerPool(): void {
    for (let i = 0; i < this.maxWorkers; i++) {
      const workerId = `worker-${crypto.randomUUID().slice(0, 8)}`;
      this.workers.set(workerId, {
        id: workerId,
        status: 'idle',
        tasksCompleted: 0,
        averageProcessingTime: 0,
        lastActivity: new Date(),
        specialization: this.assignSpecialization(i)
      });
    }
    console.log(`[Decentralized Intelligence] Initialized ${this.workers.size} virtual workers`);
  }

  private assignSpecialization(index: number): string[] {
    const specializations = [
      ['inference', 'analysis'],
      ['embedding', 'synthesis'],
      ['translation', 'emotion'],
      ['inference', 'translation', 'emotion']
    ];
    return specializations[index % specializations.length];
  }

  private startTaskScheduler(): void {
    setInterval(() => this.processQueue(), 100);
    setInterval(() => this.cleanupCompletedTasks(), 60000);
    setInterval(() => this.emitStats(), 5000);
  }

  private async processQueue(): Promise<void> {
    if (this.taskQueue.length === 0) return;

    const idleWorkers = Array.from(this.workers.values())
      .filter(w => w.status === 'idle');

    if (idleWorkers.length === 0) return;

    this.taskQueue.sort((a, b) => {
      const priorityOrder = { critical: 0, high: 1, normal: 2, low: 3 };
      return priorityOrder[a.priority] - priorityOrder[b.priority];
    });

    for (const worker of idleWorkers) {
      const task = this.findBestTaskForWorker(worker);
      if (task) {
        this.assignTaskToWorker(worker, task);
      }
    }
  }

  private findBestTaskForWorker(worker: WorkerNode): DistributedTask | undefined {
    if (worker.specialization && worker.specialization.length > 0) {
      const specializedTask = this.taskQueue.find(t => 
        worker.specialization!.includes(t.type)
      );
      if (specializedTask) {
        this.taskQueue = this.taskQueue.filter(t => t.id !== specializedTask.id);
        return specializedTask;
      }
    }

    return this.taskQueue.shift();
  }

  private async assignTaskToWorker(worker: WorkerNode, task: DistributedTask): Promise<void> {
    worker.status = 'busy';
    worker.currentTask = task.id;
    worker.lastActivity = new Date();
    this.processingTasks.set(task.id, task);

    const startTime = Date.now();

    try {
      const result = await this.executeTask(task);
      const processingTime = Date.now() - startTime;

      const taskResult: TaskResult = {
        taskId: task.id,
        success: true,
        result,
        processingTime,
        workerId: worker.id
      };

      this.completedTasks.set(task.id, taskResult);
      this.tasksCompletedTotal++;
      this.totalProcessingTime += processingTime;

      worker.tasksCompleted++;
      worker.averageProcessingTime = 
        (worker.averageProcessingTime * (worker.tasksCompleted - 1) + processingTime) / worker.tasksCompleted;

      const taskPromise = this.taskPromises.get(task.id);
      if (taskPromise) {
        clearTimeout(taskPromise.timeout);
        taskPromise.resolve(taskResult);
        this.taskPromises.delete(task.id);
      }

      this.emit('taskCompleted', taskResult);
    } catch (error: any) {
      const taskResult: TaskResult = {
        taskId: task.id,
        success: false,
        error: error.message,
        processingTime: Date.now() - startTime,
        workerId: worker.id
      };

      this.completedTasks.set(task.id, taskResult);

      const taskPromise = this.taskPromises.get(task.id);
      if (taskPromise) {
        clearTimeout(taskPromise.timeout);
        taskPromise.reject(error);
        this.taskPromises.delete(task.id);
      }

      this.emit('taskFailed', taskResult);
    } finally {
      worker.status = 'idle';
      worker.currentTask = undefined;
      this.processingTasks.delete(task.id);
    }
  }

  private async executeTask(task: DistributedTask): Promise<any> {
    switch (task.type) {
      case 'inference':
        return this.executeInferenceTask(task.payload);
      case 'analysis':
        return this.executeAnalysisTask(task.payload);
      case 'embedding':
        return this.executeEmbeddingTask(task.payload);
      case 'translation':
        return this.executeTranslationTask(task.payload);
      case 'emotion':
        return this.executeEmotionTask(task.payload);
      case 'synthesis':
        return this.executeSynthesisTask(task.payload);
      default:
        throw new Error(`Unknown task type: ${task.type}`);
    }
  }

  private async executeInferenceTask(payload: any): Promise<any> {
    await this.simulateProcessing(50, 200);
    return { processed: true, type: 'inference', payload };
  }

  private async executeAnalysisTask(payload: any): Promise<any> {
    await this.simulateProcessing(100, 300);
    return { analyzed: true, type: 'analysis', insights: [] };
  }

  private async executeEmbeddingTask(payload: any): Promise<any> {
    await this.simulateProcessing(30, 100);
    return { embedded: true, dimensions: 1536 };
  }

  private async executeTranslationTask(payload: any): Promise<any> {
    await this.simulateProcessing(80, 250);
    return { translated: true, targetLanguage: payload.targetLanguage };
  }

  private async executeEmotionTask(payload: any): Promise<any> {
    await this.simulateProcessing(40, 150);
    return { analyzed: true, emotion: 'neutral', confidence: 0.8 };
  }

  private async executeSynthesisTask(payload: any): Promise<any> {
    await this.simulateProcessing(150, 400);
    return { synthesized: true, components: payload.components?.length || 0 };
  }

  private simulateProcessing(minMs: number, maxMs: number): Promise<void> {
    const delay = minMs + Math.random() * (maxMs - minMs);
    return new Promise(resolve => setTimeout(resolve, delay));
  }

  async submitTask(
    type: DistributedTask['type'],
    payload: any,
    options?: { priority?: DistributedTask['priority']; timeout?: number }
  ): Promise<TaskResult> {
    if (this.taskQueue.length >= this.maxQueueSize) {
      throw new Error('Task queue is full');
    }

    const task: DistributedTask = {
      id: crypto.randomUUID(),
      type,
      payload,
      priority: options?.priority || 'normal',
      createdAt: new Date(),
      timeout: options?.timeout || this.defaultTimeout
    };

    this.taskQueue.push(task);
    this.emit('taskSubmitted', task);

    return new Promise((resolve, reject) => {
      const timeout = setTimeout(() => {
        this.taskPromises.delete(task.id);
        reject(new Error(`Task ${task.id} timed out`));
      }, task.timeout);

      this.taskPromises.set(task.id, { resolve, reject, timeout });
    });
  }

  async submitBatch(
    tasks: Array<{ type: DistributedTask['type']; payload: any; priority?: DistributedTask['priority'] }>
  ): Promise<TaskResult[]> {
    const promises = tasks.map(t => 
      this.submitTask(t.type, t.payload, { priority: t.priority })
    );

    return Promise.all(promises);
  }

  async parallelProcess<T>(
    items: T[],
    processor: (item: T) => Promise<any>,
    options?: { batchSize?: number; priority?: DistributedTask['priority'] }
  ): Promise<any[]> {
    const batchSize = options?.batchSize || this.maxWorkers;
    const results: any[] = [];

    for (let i = 0; i < items.length; i += batchSize) {
      const batch = items.slice(i, i + batchSize);
      const batchResults = await Promise.all(batch.map(processor));
      results.push(...batchResults);
    }

    return results;
  }

  getWorkerStatus(): WorkerNode[] {
    return Array.from(this.workers.values());
  }

  getQueueStatus(): { pending: number; processing: number; completed: number } {
    return {
      pending: this.taskQueue.length,
      processing: this.processingTasks.size,
      completed: this.completedTasks.size
    };
  }

  getStats(): ClusterStats {
    const workerArray = Array.from(this.workers.values());
    const activeWorkers = workerArray.filter(w => w.status === 'busy').length;
    const idleWorkers = workerArray.filter(w => w.status === 'idle').length;

    return {
      totalWorkers: this.workers.size,
      activeWorkers,
      idleWorkers,
      tasksInQueue: this.taskQueue.length,
      tasksProcessing: this.processingTasks.size,
      tasksCompleted: this.tasksCompletedTotal,
      averageLatency: this.tasksCompletedTotal > 0 
        ? this.totalProcessingTime / this.tasksCompletedTotal 
        : 0,
      throughput: this.calculateThroughput()
    };
  }

  private calculateThroughput(): number {
    const recentTasks = Array.from(this.completedTasks.values())
      .filter(t => Date.now() - t.processingTime < 60000);
    return recentTasks.length;
  }

  private cleanupCompletedTasks(): void {
    const maxAge = 5 * 60 * 1000;
    const now = Date.now();

    for (const [id, result] of this.completedTasks) {
      if (now - result.processingTime > maxAge) {
        this.completedTasks.delete(id);
      }
    }
  }

  private emitStats(): void {
    this.emit('stats', this.getStats());
  }

  async scaleWorkers(count: number): Promise<void> {
    const currentCount = this.workers.size;

    if (count > currentCount) {
      for (let i = currentCount; i < count; i++) {
        const workerId = `worker-${crypto.randomUUID().slice(0, 8)}`;
        this.workers.set(workerId, {
          id: workerId,
          status: 'idle',
          tasksCompleted: 0,
          averageProcessingTime: 0,
          lastActivity: new Date(),
          specialization: this.assignSpecialization(i)
        });
      }
      console.log(`[Decentralized Intelligence] Scaled up to ${this.workers.size} workers`);
    } else if (count < currentCount) {
      const workersToRemove = Array.from(this.workers.keys()).slice(count);
      for (const id of workersToRemove) {
        const worker = this.workers.get(id);
        if (worker?.status === 'idle') {
          this.workers.delete(id);
        }
      }
      console.log(`[Decentralized Intelligence] Scaled down to ${this.workers.size} workers`);
    }
  }

  getTaskResult(taskId: string): TaskResult | undefined {
    return this.completedTasks.get(taskId);
  }

  cancelTask(taskId: string): boolean {
    const queueIndex = this.taskQueue.findIndex(t => t.id === taskId);
    if (queueIndex !== -1) {
      this.taskQueue.splice(queueIndex, 1);
      const promise = this.taskPromises.get(taskId);
      if (promise) {
        clearTimeout(promise.timeout);
        promise.reject(new Error('Task cancelled'));
        this.taskPromises.delete(taskId);
      }
      return true;
    }
    return false;
  }

  async shutdown(): Promise<void> {
    console.log('[Decentralized Intelligence] Shutting down distributed network...');

    for (const [id, promise] of this.taskPromises) {
      clearTimeout(promise.timeout);
      promise.reject(new Error('Network shutdown'));
    }

    this.taskQueue = [];
    this.taskPromises.clear();
    this.workers.clear();

    console.log('[Decentralized Intelligence] Network shutdown complete');
  }
}

export const decentralizedIntelligence = new DecentralizedIntelligenceNetwork();

