@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&display=swap');
@import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500;600&display=swap');
@import './styles/premium-aerospace.css';

@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  :root {
    --background: 0 0% 4%;
    --foreground: 0 0% 98%;
    --card: 220 20% 6%;
    --card-foreground: 0 0% 98%;
    --popover: 220 20% 6%;
    --popover-foreground: 0 0% 98%;
    --primary: 190 100% 50%;
    --primary-foreground: 220 20% 4%;
    --secondary: 260 80% 55%;
    --secondary-foreground: 0 0% 98%;
    --muted: 220 15% 12%;
    --muted-foreground: 0 0% 60%;
    --accent: 190 100% 50%;
    --accent-foreground: 220 20% 4%;
    --destructive: 0 72% 51%;
    --destructive-foreground: 0 0% 98%;
    --border: 220 15% 15%;
    --input: 220 15% 10%;
    --ring: 190 100% 50%;
    --radius: 0.625rem;
    --chart-1: 190 100% 50%;
    --chart-2: 160 84% 39%;
    --chart-3: 35 92% 50%;
    --chart-4: 260 80% 55%;
    --chart-5: 340 82% 52%;
  }
}

@layer base {
  * {
    @apply border-border;
  }

  html {
    scroll-behavior: smooth;
  }

  body {
    @apply bg-background text-foreground antialiased;
    font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'SF Pro Display', 'Segoe UI', sans-serif;
    font-feature-settings: 'ss01' on, 'ss02' on, 'cv01' on;
    background: linear-gradient(135deg, #0a0a0f 0%, #0d0d14 50%, #0a0a0f 100%);
    min-height: 100vh;
  }
}

@layer utilities {
  .text-gradient-premium {
    @apply bg-gradient-to-r from-cyan-400 via-blue-400 to-purple-500 bg-clip-text text-transparent;
  }

  .text-gradient-gold {
    @apply bg-gradient-to-r from-amber-400 via-yellow-300 to-orange-400 bg-clip-text text-transparent;
  }

  .glow-cyan {
    box-shadow: 0 0 40px rgba(0, 212, 255, 0.15), 0 0 80px rgba(0, 212, 255, 0.05);
  }

  .glow-purple {
    box-shadow: 0 0 40px rgba(124, 58, 237, 0.15), 0 0 80px rgba(124, 58, 237, 0.05);
  }

  .glass-ultra {
    @apply bg-white/[0.03] backdrop-blur-2xl border border-white/[0.08];
  }

  .glass-panel-premium {
    @apply bg-[#12121a]/85 backdrop-blur-xl border border-white/[0.08] shadow-2xl;
  }

  /* Custom Scrollbar Styles */
  .scrollbar-thin {
    scrollbar-width: thin;
    scrollbar-color: #3a3a3c transparent;
  }

  .scrollbar-thin::-webkit-scrollbar {
    width: 6px;
    height: 6px;
  }

  .scrollbar-thin::-webkit-scrollbar-track {
    background: transparent;
    border-radius: 3px;
  }

  .scrollbar-thin::-webkit-scrollbar-thumb {
    background: #3a3a3c;
    border-radius: 3px;
  }

  .scrollbar-thin::-webkit-scrollbar-thumb:hover {
    background: #48484a;
  }

  .scrollbar-thumb-\[\#3a3a3c\]::-webkit-scrollbar-thumb {
    background: #3a3a3c;
  }

  .hover\:scrollbar-thumb-\[\#48484a\]:hover::-webkit-scrollbar-thumb {
    background: #48484a;
  }
}

