  color: var(--label-tertiary);
  margin-right: var(--space-2);
}

.console-info { color: var(--system-blue); }
.console-success { color: var(--system-green); }
.console-warning { color: var(--system-orange); }
.console-error { color: var(--system-red); }

/* Buttons */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-2);
  padding: var(--space-3) var(--space-5);
  font-size: 15px;
  font-weight: 600;
  font-family: var(--font-system);
  letter-spacing: -0.01em;
  border: none;
  border-radius: var(--radius-md);
  cursor: pointer;
  transition: all 0.15s ease;
}

.btn:active {
  transform: scale(0.98);
}

.btn:disabled {
  opacity: 0.35;
  cursor: not-allowed;
  transform: none;
}

.btn-primary {
  background: var(--system-blue);
