/* Input Fields */
.input {
  width: 100%;
  padding: var(--space-3) var(--space-4);
  font-size: 15px;
  font-family: var(--font-system);
  color: var(--label-primary);
  background: var(--fill-tertiary);
  border: none;
  border-radius: var(--radius-md);
