class Domain(str, Enum):
    MEDICAL = "medical"
    ENGINEERING = "engineering"
    SCIENTIFIC = "scientific"
    INDUSTRIAL = "industrial"
    BIOLOGICAL = "biological"
    CHEMICAL = "chemical"


class ViewType(str, Enum):
