                    'thickness_cm': 7,
                    'thickness_range': (6, 8),
                    'mass_g': 300,
                    'mass_range': (250, 350)
                },
                'chambers': {
                    'right_atrium': {
                        'wall_thickness_mm': 2,
                        'volume_ml': (40, 60),
                        'location': 'anterior_superior_right',
